export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new Error("maxTokens must be positive");
    if (options.refillRate <= 0) throw new Error("refillRate must be positive");
    if (options.refillIntervalMs <= 0) throw new Error("refillIntervalMs must be positive");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new Error("tokens must be positive");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new Error("tokens must be positive"));
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new Error(`Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const waitMs = Math.max(
          1,
          intervalsNeeded * this.refillIntervalMs -
            (Date.now() - this.lastRefillTime)
        );

        setTimeout(attempt, waitMs);
      };

      attempt();
    });
  }
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{
    tokens: number;
    resolve: () => void;
    reject: (err: Error) => void;
  }>;
  private timerHandle: ReturnType<typeof setTimeout> | null;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens < 0) {
      throw new RangeError(
        `maxTokens must be a non-negative finite number, got ${options.maxTokens}`
      );
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError(
        `refillRate must be a non-negative finite number, got ${options.refillRate}`
      );
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(
        `refillIntervalMs must be a positive finite number, got ${options.refillIntervalMs}`
      );
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.timerHandle = null;
  }

  private refill(): void {
    if (this.refillRate === 0) return;

    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed >= this.refillIntervalMs) {
      const intervals = Math.floor(elapsed / this.refillIntervalMs);
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      // Advance lastRefillTime by only the consumed intervals to preserve
      // sub-interval elapsed time — avoids silently discarding partial progress.
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(
        `tokens must be a non-negative finite number, got ${tokens}`
      );
    }

    // Zero-cost consume always succeeds regardless of bucket state.
    if (tokens === 0) return true;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    // Cancel any pending timer — drainQueue will reschedule if still needed.
    if (this.timerHandle !== null) {
      clearTimeout(this.timerHandle);
      this.timerHandle = null;
    }

    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError(`tokens must be a non-negative finite number, got ${tokens}`)
      );
    }

    // A request exceeding maxTokens can never be satisfied — reject immediately
    // rather than hanging indefinitely and silently.
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; ` +
          `this request can never be satisfied`
        )
      );
    }

    // Fast path — no queue overhead if tokens are available right now.
    if (this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    // With a refillRate of 0 the bucket never gains tokens; reject to avoid
    // a promise that will never resolve.
    if (this.refillRate === 0) {
      return Promise.reject(
        new Error(
          `Cannot wait for ${tokens} tokens: refillRate is 0 and only ` +
          `${this.currentTokens} token(s) are currently available`
        )
      );
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextCheck();
    });
  }

  /**
   * Computes the minimum milliseconds to wait before the head-of-queue waiter
   * could possibly be satisfied. Does NOT mutate state.
   */
  private computeWaitMs(): number {
    const head = this.waitQueue[0];
    const tokensNeeded = head.tokens - this.currentTokens;

    // How many full refill intervals are required to cover the deficit?
    const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);

    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const msUntilFirstRefill = Math.max(0, this.refillIntervalMs - elapsed);

    // First interval may be partially elapsed; remaining are full intervals.
    return msUntilFirstRefill + (intervalsNeeded - 1) * this.refillIntervalMs;
  }

  /**
   * Schedules exactly one timer for the head-of-queue waiter. Idempotent —
   * will not schedule a second timer if one is already pending.
   */
  private scheduleNextCheck(): void {
    if (this.timerHandle !== null || this.waitQueue.length === 0) return;

    const waitMs = this.computeWaitMs();

    // +1 ms cushion absorbs timer jitter; the actual token check inside
    // drainQueue always re-evaluates real elapsed time, so this is safe.
    this.timerHandle = setTimeout(() => {
      this.timerHandle = null;
      this.drainQueue();
    }, waitMs + 1);
  }

  /**
   * Attempts to satisfy as many head-of-queue waiters as possible in FIFO
   * order, then reschedules if the queue is not empty.
   */
  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      this.refill();

      const head = this.waitQueue[0];

      if (this.currentTokens >= head.tokens) {
        this.currentTokens -= head.tokens;
        this.waitQueue.shift();
        // Resolve after dequeuing so that any synchronous code in the
        // resolved callback can't observe a stale queue state.
        head.resolve();
      } else {
        // Head cannot be satisfied yet; preserve FIFO ordering by stopping.
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextCheck();
    }
  }
}

export default RateLimiter;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (reason: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private drainTimeout: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (options === null || typeof options !== "object") {
      throw new TypeError("options must be a non-null object");
    }

    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got: ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(`refillRate must be a positive finite number, got: ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got: ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.drainTimeout = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed >= this.refillIntervalMs) {
      const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      // Advance lastRefillTime by whole intervals only, preserving fractional elapsed time
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  private validateTokenCount(tokens: number, label: string): void {
    if (!Number.isFinite(tokens)) {
      throw new RangeError(`${label} must be a finite number, got: ${tokens}`);
    }
    if (tokens < 0) {
      throw new RangeError(`${label} must be non-negative, got: ${tokens}`);
    }
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenCount(tokens, "tokens");

    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    if (this.drainTimeout !== null) {
      clearTimeout(this.drainTimeout);
      this.drainTimeout = null;
    }
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainWaiters();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    let validationError: RangeError | null = null;
    try {
      this.validateTokenCount(tokens, "tokens");
    } catch (err) {
      validationError = err as RangeError;
    }
    if (validationError !== null) {
      return Promise.reject(validationError);
    }

    if (tokens === 0) return Promise.resolve();

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); ` +
            `this request can never be satisfied`
        )
      );
    }

    // Fast path: no pending waiters and tokens are available
    if (this.waitQueue.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextDrain();
    });
  }

  private drainWaiters(): void {
    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0]!;
      this.applyRefill();

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        // Cannot satisfy the head waiter yet; stop and reschedule
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextDrain();
    }
  }

  private scheduleNextDrain(): void {
    // Only one scheduled drain at a time
    if (this.drainTimeout !== null) return;
    if (this.waitQueue.length === 0) return;

    const waiter = this.waitQueue[0]!;

    this.applyRefill();

    const tokensNeeded = waiter.tokens - this.currentTokens;
    if (tokensNeeded <= 0) {
      // Tokens already available — microtask to avoid re-entrancy issues
      this.drainTimeout = setTimeout(() => {
        this.drainTimeout = null;
        this.drainWaiters();
      }, 0);
      return;
    }

    // How many full refill intervals until we accumulate enough tokens
    const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);

    // Time remaining until the next refill interval fires
    const elapsedSinceLastRefill = Date.now() - this.lastRefillTime;
    const timeUntilNextRefill = Math.max(0, this.refillIntervalMs - elapsedSinceLastRefill);

    // After the next refill, we need (intervalsNeeded - 1) more intervals
    const msUntilReady = timeUntilNextRefill + (intervalsNeeded - 1) * this.refillIntervalMs;

    this.drainTimeout = setTimeout(() => {
      this.drainTimeout = null;
      this.drainWaiters();
    }, Math.max(0, msUntilReady));
  }
}

export default RateLimiter;

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be positive");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be positive");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be positive");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be positive");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be positive"));
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise((resolve) => {
      const attempt = (): void => {
        this.refill();

        if (this.currentTokens >= tokens) {
          this.currentTokens -= tokens;
          resolve();
          return;
        }

        const tokensNeeded = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
        const elapsed = Date.now() - this.lastRefillTime;
        const msUntilNextInterval = this.refillIntervalMs - (elapsed % this.refillIntervalMs);
        const delay = msUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs;

        setTimeout(attempt, Math.max(0, delay));
      };

      attempt();
    });
  }
}

