export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: WaitEntry[];
  private scheduledTimeout: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(
        `maxTokens must be a positive finite number, got ${options.maxTokens}`
      );
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError(
        `refillRate must be a non-negative finite number, got ${options.refillRate}`
      );
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(
        `refillIntervalMs must be a positive finite number, got ${options.refillIntervalMs}`
      );
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledTimeout = null;
  }

  private _refill(): void {
    const now = Date.now();
    // Guard against clock skew / monotonicity violations
    const elapsed = Math.max(0, now - this.lastRefillTime);
    if (elapsed > 0 && this.refillRate > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    }
    this.lastRefillTime = now;
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(
        `tokens must be a non-negative finite number, got ${tokens}`
      );
    }
    if (tokens === 0) return true;

    this._refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this._refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Process any pending waiters that can now be satisfied
    this._tryProcessQueue();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(
        `tokens must be a non-negative finite number, got ${tokens}`
      );
    }
    if (tokens === 0) return;
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens}): can never be satisfied`
      );
    }

    this._refill();

    // With zero refillRate, tokens only come from reset(). We cannot schedule
    // a meaningful wait, so only allow immediate consumption with no contention.
    if (this.refillRate === 0) {
      if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return;
      }
      throw new Error(
        `Cannot wait: refillRate is 0 and insufficient tokens are available (${this.currentTokens} < ${tokens})`
      );
    }

    return new Promise<void>((resolve, reject) => {
      // Fast path: queue is empty and tokens are available right now
      if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        resolve();
        return;
      }

      this.waitQueue.push({ tokens, resolve, reject });
      this._scheduleQueueProcessing();
    });
  }

  private _tryProcessQueue(): void {
    this._refill();

    while (this.waitQueue.length > 0) {
      const entry = this.waitQueue[0];
      if (this.currentTokens >= entry.tokens) {
        this.currentTokens -= entry.tokens;
        this.waitQueue.shift();
        entry.resolve();
      } else {
        // Cannot satisfy the head of the queue; stop here to preserve FIFO ordering
        break;
      }
    }

    // If unsatisfied waiters remain, ensure a timeout is scheduled
    if (this.waitQueue.length > 0) {
      this._scheduleQueueProcessing();
    }
  }

  private _scheduleQueueProcessing(): void {
    // Avoid double-scheduling; the existing timeout will re-evaluate after firing
    if (this.scheduledTimeout !== null || this.waitQueue.length === 0) return;

    const entry = this.waitQueue[0];
    const needed = entry.tokens - this.currentTokens;

    if (needed <= 0) {
      // Should be immediately processable; defer one turn to avoid deep stack
      this.scheduledTimeout = setTimeout(() => {
        this.scheduledTimeout = null;
        this._tryProcessQueue();
      }, 0);
      return;
    }

    // Compute the soonest moment enough tokens will exist for the queue head.
    // Add 1ms buffer against sub-millisecond floating-point under-estimation.
    const waitMs = Math.ceil((needed / this.refillRate) * this.refillIntervalMs) + 1;

    this.scheduledTimeout = setTimeout(() => {
      this.scheduledTimeout = null;
      this._tryProcessQueue();
    }, waitMs);
  }
}

export default RateLimiter;

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function sanitizeUrl(url: string): string {
  const trimmed = url.trim();
  return /^(javascript|vbscript|data):/i.test(trimmed) ? "#" : trimmed;
}

function processInline(text: string): string {
  // Phase 1: extract and protect code spans (must be first — nothing processes inside them)
  const codeSpans: string[] = [];
  let s = text.replace(/`([^`]+)`/g, (_, code) => {
    const idx = codeSpans.length;
    codeSpans.push(`<code>${escapeHtml(code)}</code>`);
    return `\x00C${idx}\x00`;
  });

  // Phase 2: extract links before HTML-escaping so raw URLs are preserved
  const links: string[] = [];
  s = s.replace(/\[([^\]]*)\]\(([^)]*)\)/g, (_, linkText, url) => {
    const idx = links.length;
    const safeUrl = escapeHtml(sanitizeUrl(url));
    links.push(`<a href="${safeUrl}">${escapeHtml(linkText)}</a>`);
    return `\x00L${idx}\x00`;
  });

  // Phase 3: escape HTML entities in remaining plain text
  s = escapeHtml(s);

  // Phase 4: bold before italic to avoid partial greedy collisions
  // Use negative lookaround to prevent matching inside *** sequences
  s = s.replace(/(?<!\*)\*\*([^*\n]+)\*\*(?!\*)/g, "<strong>$1</strong>");
  s = s.replace(/(?<!\w)__([^_\n]+)__(?!\w)/g, "<strong>$1</strong>");
  s = s.replace(/(?<!\*)\*([^*\n]+)\*(?!\*)/g, "<em>$1</em>");
  s = s.replace(/(?<!\w)_([^_\n]+)_(?!\w)/g, "<em>$1</em>");

  // Phase 5: restore protected spans
  s = s.replace(/\x00L(\d+)\x00/g, (_, i) => links[+i] ?? "");
  s = s.replace(/\x00C(\d+)\x00/g, (_, i) => codeSpans[+i] ?? "");

  return s;
}

function buildList(lines: string[]): string {
  let html = "";
  // Stack tracks indent levels of open <ul> elements
  const stack: number[] = [];

  for (const line of lines) {
    const m = line.match(/^(\s*)([-*])\s+(.*)/);
    if (!m) continue;

    const indent = m[1].length;
    const content = processInline(m[3]);

    if (stack.length === 0) {
      html += `<ul><li>${content}`;
      stack.push(indent);
    } else {
      const top = stack[stack.length - 1];
      if (indent > top) {
        // Deeper nesting: open a new list inside the current <li>
        html += `<ul><li>${content}`;
        stack.push(indent);
      } else if (indent === top) {
        // Same level: close previous item and open new one
        html += `</li><li>${content}`;
      } else {
        // Shallower: close inner lists until we reach this indent level
        // Keep at least one entry so the base list stays open
        while (stack.length > 1 && stack[stack.length - 1] > indent) {
          html += "</li></ul>";
          stack.pop();
        }
        html += `</li><li>${content}`;
      }
    }
  }

  // Close all remaining open list elements
  while (stack.length > 0) {
    html += "</li></ul>";
    stack.pop();
  }

  return html;
}

export default function parseMarkdown(input: string): string {
  if (typeof input !== "string" || input.length === 0) return "";

  // Normalize all line endings to \n
  const text = input.replace(/\r\n/g, "\n").replace(/\r/g, "\n");

  // Extract fenced code blocks early; protect them from all further processing.
  // Supports optional language identifier and variable-length fence (

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

function rangeArray(start: number, end: number): number[] {
  if (start > end) throw new Error(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function validateValue(value: number, fieldName: FieldName): number {
  const { min, max } = FIELD_RANGES[fieldName];
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of range [${min}-${max}] for field "${fieldName}"`
    );
  }
  return value;
}

function parseSegment(segment: string, fieldName: FieldName): number[] {
  const { min, max } = FIELD_RANGES[fieldName];

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step: */n or range/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in "${segment}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((n) => parseInt(n, 10));
      if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range in "${segment}"`);
      start = validateValue(s, fieldName);
      end = validateValue(e, fieldName);
    } else {
      start = validateValue(parseInt(rangePart, 10), fieldName);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = validateValue(parseInt(startStr, 10), fieldName);
    const end = validateValue(parseInt(endStr, 10), fieldName);
    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${segment}" for field "${fieldName}"`);
  }

  // Normalize dayOfWeek: 7 is an alias for 0 (Sunday)
  if (fieldName === "dayOfWeek" && value === 7) {
    return [0];
  }

  return [validateValue(value, fieldName)];
}

function parseField(field: string, fieldName: FieldName): number[] {
  const segments = field.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment.trim(), fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}. Format: "minute hour dayOfMonth month dayOfWeek"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  return {
    minute: parseField(minuteField, "minute"),
    hour: parseField(hourField, "hour"),
    dayOfMonth: parseField(domField, "dayOfMonth"),
    month: parseField(monthField, "month"),
    dayOfWeek: parseField(dowField, "dayOfWeek"),
  };
}

/**
 * Converts a subset of Markdown to HTML.
 */
export function parseMarkdown(markdown: string): string {
  if (typeof markdown !== "string") return "";

  const lines = markdown.split("\n");
  const blocks = extractBlocks(lines);
  return blocks.map(renderBlock).filter((s) => s !== "").join("\n");
}

// ---------------------------------------------------------------------------
// Block types
// ---------------------------------------------------------------------------

type Block =
  | { type: "heading"; level: 1 | 2 | 3 | 4 | 5 | 6; content: string }
  | { type: "paragraph"; lines: string[] }
  | { type: "code_block"; lang: string; code: string }
  | { type: "list"; items: ListItem[] };

interface ListItem {
  content: string;
  indent: number;
  children: ListItem[];
}

// ---------------------------------------------------------------------------
// Block extraction
// ---------------------------------------------------------------------------

function extractBlocks(lines: string[]): Block[] {
  const blocks: Block[] = [];
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];

    // Fenced code block
    const fenceMatch = line.match(/^(`{3,}|~{3,})([\w-]*)\s*$/);
    if (fenceMatch) {
      const fence = fenceMatch[1];
      const lang = fenceMatch[2] ?? "";
      const codeLines: string[] = [];
      i++;
      while (i < lines.length && !lines[i].startsWith(fence)) {
        codeLines.push(lines[i]);
        i++;
      }
      i++; // skip closing fence
      blocks.push({ type: "code_block", lang, code: codeLines.join("\n") });
      continue;
    }

    // Blank line — skip
    if (line.trim() === "") {
      i++;
      continue;
    }

    // ATX Heading
    const headingMatch = line.match(/^(#{1,6})\s+(.*?)\s*#*\s*$/);
    if (headingMatch) {
      const level = Math.min(headingMatch[1].length, 6) as 1 | 2 | 3 | 4 | 5 | 6;
      blocks.push({ type: "heading", level, content: headingMatch[2] ?? "" });
      i++;
      continue;
    }

    // Unordered list
    if (isListLine(line)) {
      const rawItems: { indent: number; content: string }[] = [];
      while (i < lines.length && (isListLine(lines[i]) || isContinuationLine(lines[i], rawItems))) {
        const current = lines[i];
        const listMatch = current.match(/^(\s*)[*\-+]\s+(.*)/);
        if (listMatch) {
          rawItems.push({ indent: listMatch[1].length, content: listMatch[2] ?? "" });
        } else if (current.trim() !== "") {
          // continuation text appended to last item
          if (rawItems.length > 0) {
            rawItems[rawItems.length - 1].content += " " + current.trim();
          }
        }
        i++;
      }
      blocks.push({ type: "list", items: buildListTree(rawItems) });
      continue;
    }

    // Paragraph — consume until blank line or block-level element
    const paraLines: string[] = [];
    while (
      i < lines.length &&
      lines[i].trim() !== "" &&
      !isListLine(lines[i]) &&
      !lines[i].match(/^#{1,6}\s/) &&
      !lines[i].match(/^(`{3,}|~{3,})/)
    ) {
      paraLines.push(lines[i]);
      i++;
    }
    if (paraLines.length > 0) {
      blocks.push({ type: "paragraph", lines: paraLines });
    }
  }

  return blocks;
}

function isListLine(line: string): boolean {
  return /^\s*[*\-+]\s+/.test(line);
}

function isContinuationLine(
  line: string,
  items: { indent: number; content: string }[]
): boolean {
  if (items.length === 0) return false;
  if (line.trim() === "") return false;
  // A non-list, non-blank line indented more than the list marker is continuation
  const indentMatch = line.match(/^(\s*)/);
  const indent = indentMatch ? indentMatch[1].length : 0;
  const lastIndent = items[items.length - 1].indent;
  return indent > lastIndent && !isListLine(line);
}

// ---------------------------------------------------------------------------
// List tree builder
// ---------------------------------------------------------------------------

function buildListTree(
  rawItems: { indent: number; content: string }[]
): ListItem[] {
  const root: ListItem[] = [];
  const stack: { indent: number; item: ListItem }[] = [];

  for (const raw of rawItems) {
    const item: ListItem = { content: raw.content, indent: raw.indent, children: [] };

    while (stack.length > 0 && stack[stack.length - 1].indent >= raw.indent) {
      stack.pop();
    }

    if (stack.length === 0) {
      root.push(item);
    } else {
      stack[stack.length - 1].item.children.push(item);
    }

    stack.push({ indent: raw.indent, item });
  }

  return root;
}

// ---------------------------------------------------------------------------
// Block rendering
// ---------------------------------------------------------------------------

function renderBlock(block: Block): string {
  switch (block.type) {
    case "heading":
      return `<h${block.level}>${renderInline(block.content)}</h${block.level}>`;

    case "paragraph": {
      const content = block.lines.join(" ").trim();
      return content ? `<p>${renderInline(content)}</p>` : "";
    }

    case "code_block": {
      const escaped = escapeHtml(block.code);
      const langAttr = block.lang ? ` class="language-${escapeAttr(block.lang)}"` : "";
      return `<pre><code${langAttr}>${escaped}</code></pre>`;
    }

    case "list":
      return renderList(block.items);
  }
}

function renderList(items: ListItem[]): string {
  if (items.length === 0) return "";
  const inner = items
    .map((item) => {
      const children = item.children.length > 0 ? "\n" + renderList(item.children) : "";
      return `<li>${renderInline(item.content)}${children}</li>`;
    })
    .join("\n");
  return `<ul>\n${inner}\n</ul>`;
}

// ---------------------------------------------------------------------------
// Inline rendering
// ---------------------------------------------------------------------------

function renderInline(text: string): string {
  if (typeof text !== "string") return "";

  // Process inline elements using a token-based approach
  return processInline(text);
}

function processInline(text: string): string {
  // We process inline elements left-to-right, consuming the string
  let result = "";
  let i = 0;

  while (i < text.length) {
    const ch = text[i];

    // Escape HTML entities for raw characters
    // Code span: `code`
    if (ch === "`") {
      const end = text.indexOf("`", i + 1);
      if (end !== -1) {
        const code = text.slice(i + 1, end);
        result += `<code>${escapeHtml(code)}</code>`;
        i = end + 1;
        continue;
      }
    }

    // Bold + Italic combinations: ***text*** or ___text___
    if (
      (ch === "*" || ch === "_") &&
      text[i + 1] === ch &&
      text[i + 2] === ch
    ) {
      const delim = ch.repeat(3);
      const end = findDelimiter(text, delim, i + 3, ch);
      if (end !== -1) {
        const inner = processInline(text.slice(i + 3, end));
        result += `<strong><em>${inner}</em></strong>`;
        i = end + 3;
        continue;
      }
    }

    // Bold: **text** or __text__
    if ((ch === "*" || ch === "_") && text[i + 1] === ch) {
      const delim = ch.repeat(2);
      const end = findDelimiter(text, delim, i + 2, ch);
      if (end !== -1) {
        const inner = processInline(text.slice(i + 2, end));
        result += `<strong>${inner}</strong>`;
        i = end + 2;
        continue;
      }
    }

    // Italic: *text* or _text_
    // For underscore italic, only match when surrounded by word boundaries
    if (ch === "*" || ch === "_") {
      const isUnderscore = ch === "_";
      if (!isUnderscore || canOpenUnderscore(text, i)) {
        const end = findSingleDelimiter(text, ch, i + 1, isUnderscore);
        if (end !== -1) {
          const inner = processInline(text.slice(i + 1, end));
          result += `<em>${inner}</em>`;
          i = end + 1;
          continue;
        }
      }
    }

    // Link: [text](url) or [text](url "title")
    if (ch === "[") {
      const linkResult = tryParseLink(text, i);
      if (linkResult !== null) {
        result += linkResult.html;
        i = linkResult.end;
        continue;
      }
    }

    // Raw HTML entity escape
    if (ch === "&") {
      result += "&amp;";
      i++;
      continue;
    }
    if (ch === "<") {
      result += "&lt;";
      i++;
      continue;
    }
    if (ch === ">") {
      result += "&gt;";
      i++;
      continue;
    }

    result += ch;
    i++;
  }

  return result;
}

function canOpenUnderscore(text: string, i: number): boolean {
  // Underscore italic should not open inside a word
  const prev = i > 0 ? text[i - 1] : " ";
  return /\s|^/.test(prev) || !/\w/.test(prev);
}

function findDelimiter(
  text: string,
  delim: string,
  start: number,
  _delimChar: string
): number {
  let i = start;
  while (i <= text.length - delim.length) {
    if (text.slice(i, i + delim.length) === delim) {
      // Make sure it's not followed by the same delimiter char (longer run)
      if (text[i + delim.length] !== _delimChar) {
        return i;
      }
    }
    i++;
  }
  return -1;
}

function findSingleDelimiter(
  text: string,
  delim: string,
  start: number,
  isUnderscore: boolean
): number {
  for (let i = start; i < text.length; i++) {
    if (text[i] === delim && text[i + 1] !== delim) {
      if (!isUnderscore || canCloseUnderscore(text, i)) {
        return i;
      }
    }
  }
  return -1;
}

function canCloseUnderscore(text: string, i: number): boolean {
  const next = i + 1 < text.length ? text[i + 1] : " ";
  return /\s|$/.test(next) || !/\w/.test(next);
}

interface LinkResult {
  html: string;
  end: number;
}

function tryParseLink(text: string, start: number): LinkResult | null {
  // Find closing ]
  let depth = 0;
  let textEnd = -1;
  for (let i = start + 1; i < text.length; i++) {
    if (text[i] === "[") depth++;
    else if (text[i] === "]") {
      if (depth === 0) {
        textEnd = i;
        break;
      }
      depth--;
    }
  }
  if (textEnd === -1) return null;
  if (text[textEnd + 1] !== "(") return null;

  const parenOpen = textEnd + 1;
  let parenDepth = 0;
  let parenClose = -1;
  for (let i = parenOpen + 1; i < text.length; i++) {
    if (text[i] === "(") parenDepth++;
    else if (text[i] === ")") {
      if (parenDepth === 0) {
        parenClose = i;
        break;
      }
      parenDepth--;
    }
  }
  if (parenClose === -1) return null;

  const linkContent = text.slice(parenOpen + 1, parenClose).trim();
  let url = "";
  let title = "";

  // Parse optional title: url "title" or url 'title'
  const titleMatch = linkContent.match(/^(.*?)\s+"([^"]*)"$/) ||
    linkContent.match(/^(.*?)\s+'([^']*)'$/);
  if (titleMatch) {
    url = titleMatch[1].trim();
    title = titleMatch[2];
  } else {
    url = linkContent;
  }

  const safeUrl = sanitizeUrl(url);
  const linkText = processInline(text.slice(start + 1, textEnd));
  const titleAttr = title ? ` title="${escapeAttr(title)}"` : "";
  const html = `<a href="${escapeAttr(safeUrl)}"${titleAttr}>${linkText}</a>`;

  return { html, end: parenClose + 1 };
}

// ---------------------------------------------------------------------------
// Utilities
// ---------------------------------------------------------------------------

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function escapeAttr(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

function sanitizeUrl(url: string): string {
  const trimmed = url.trim();
  try {
    // Allow relative URLs and safe protocols
    if (/^(https?|ftp|mailto):\/\//i.test(trimmed)) return trimmed;
    if (/^[/.]/.test(trimmed)) return trimmed;
    if (/^#/.test(trimmed)) return trimmed;
    if (/^[a-zA-Z0-9]/i.test(trimmed) && !/^javascript:/i.test(trimmed)) {
      return trimmed;
    }
    // Block javascript: and other dangerous protocols
    return "#";
  } catch {
    return "#";
  }
}

export default parseMarkdown;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldMeta {
  name: keyof CronFields;
  min: number;
  max: number;
}

const FIELD_META: readonly FieldMeta[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
] as const;

function parseNonNegativeInt(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Expected non-negative integer in ${context}, got: "${raw}"`);
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer overflow in ${context}: "${raw}"`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in ${context}`);
  }
}

function expandRange(start: number, end: number, step: number, context: string): number[] {
  if (step <= 0) throw new Error(`Step must be >= 1 in ${context}, got: ${step}`);
  if (start > end) throw new Error(`Range start (${start}) exceeds end (${end}) in ${context}`);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(expr: string, min: number, max: number, fieldName: string): number[] {
  const context = `field "${fieldName}" segment "${expr}"`;

  // Step expression: "*/n", "a-b/n", or "a/n"
  if (expr.includes("/")) {
    const slashAt = expr.indexOf("/");
    const lhs = expr.slice(0, slashAt);
    const rhs = expr.slice(slashAt + 1);

    if (lhs === "" || rhs === "") {
      throw new Error(`Malformed step expression in ${context}`);
    }
    if (rhs.includes("/")) {
      throw new Error(`Multiple slashes not allowed in ${context}`);
    }

    const step = parseNonNegativeInt(rhs, context);

    if (lhs === "*") {
      return expandRange(min, max, step, context);
    }

    if (lhs.includes("-")) {
      const dashAt = lhs.indexOf("-");
      const startStr = lhs.slice(0, dashAt);
      const endStr   = lhs.slice(dashAt + 1);
      if (startStr === "" || endStr === "") {
        throw new Error(`Malformed range in ${context}`);
      }
      const start = parseNonNegativeInt(startStr, context);
      const end   = parseNonNegativeInt(endStr,   context);
      assertInRange(start, min, max, context);
      assertInRange(end,   min, max, context);
      return expandRange(start, end, step, context);
    }

    // "a/n" — start at a, step to max
    const start = parseNonNegativeInt(lhs, context);
    assertInRange(start, min, max, context);
    return expandRange(start, max, step, context);
  }

  // Wildcard
  if (expr === "*") {
    return expandRange(min, max, 1, context);
  }

  // Plain range "a-b"
  if (expr.includes("-")) {
    const dashAt = expr.indexOf("-");
    const startStr = expr.slice(0, dashAt);
    const endStr   = expr.slice(dashAt + 1);
    if (startStr === "" || endStr === "") {
      throw new Error(`Malformed range in ${context}`);
    }
    const start = parseNonNegativeInt(startStr, context);
    const end   = parseNonNegativeInt(endStr,   context);
    assertInRange(start, min, max, context);
    assertInRange(end,   min, max, context);
    return expandRange(start, end, 1, context);
  }

  // Single value
  const value = parseNonNegativeInt(expr, context);
  assertInRange(value, min, max, context);
  return [value];
}

function parseField(expr: string, min: number, max: number, fieldName: string): number[] {
  if (expr === "" || expr.trim() === "") {
    throw new Error(`Empty expression for field "${fieldName}"`);
  }

  // Comma-separated list — each segment is parsed independently, then deduplicated
  const segments = expr.split(",");
  const seen = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new Error(`Empty segment in comma list for field "${fieldName}"`);
    }
    for (const v of parseSegment(trimmed, min, max, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error("parseCron: expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("parseCron: expression must not be empty");
  }

  const tokens = trimmed.split(/\s+/);
  if (tokens.length !== 5) {
    throw new Error(
      `parseCron: expected exactly 5 fields, got ${tokens.length} in: "${expression}"`
    );
  }

  const result = {} as CronFields;
  for (let i = 0; i < FIELD_META.length; i++) {
    const { name, min, max } = FIELD_META[i];
    result[name] = parseField(tokens[i], min, max, name);
  }
  return result;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Array<{
    tokens: number;
    resolve: () => void;
    reject: (err: Error) => void;
    timer: ReturnType<typeof setTimeout> | null;
  }>;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError("refillRate must be a finite positive number");
    }
    if (
      !Number.isFinite(options.refillIntervalMs) ||
      options.refillIntervalMs <= 0
    ) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waiters = [];
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    // Guard against clock skew or same-tick calls — never subtract tokens
    if (elapsed > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + tokensToAdd
      );
      this.lastRefillTime = now;
    }
  }

  private msUntilAvailable(needed: number): number {
    const deficit = needed - this.currentTokens;
    if (deficit <= 0) return 0;
    return (deficit / this.refillRate) * this.refillIntervalMs;
  }

  private processQueue(): void {
    this.refill();

    while (this.waiters.length > 0) {
      const waiter = this.waiters[0];

      if (this.currentTokens >= waiter.tokens) {
        this.waiters.shift();
        if (waiter.timer !== null) {
          clearTimeout(waiter.timer);
          waiter.timer = null;
        }
        this.currentTokens -= waiter.tokens;
        // Resolve after internal state is updated so re-entrant calls see
        // correct token count. Promise resolution is a microtask so this
        // executes synchronously from the queue's perspective.
        waiter.resolve();
      } else {
        // Maintain FIFO — do not skip the head waiter even if later waiters
        // could be satisfied with fewer tokens; that would starve the front.
        if (waiter.timer === null) {
          const delay = this.msUntilAvailable(waiter.tokens);
          // +1 ms as a buffer against floating-point refill under-estimates
          waiter.timer = setTimeout(() => {
            waiter.timer = null;
            this.processQueue();
          }, Math.ceil(delay) + 1);
        }
        break;
      }
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    // A request exceeding capacity can never succeed, fail fast
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Wake waiting promises — the bucket is now full
    this.processQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError("tokens must be a finite non-negative number")
      );
    }
    // Detect the permanently-unsatisfiable case up front to avoid a
    // promise that hangs forever and leaks a queue slot + timer.
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; ` +
            `this promise would never resolve`
        )
      );
    }

    this.refill();

    // Fast path: queue is empty and we have enough tokens right now
    if (this.waiters.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      const waiter = {
        tokens,
        resolve,
        reject,
        timer: null as ReturnType<typeof setTimeout> | null,
      };
      this.waiters.push(waiter);

      // Only the head waiter drives scheduling; all others wait their turn.
      if (this.waiters.length === 1) {
        const delay = this.msUntilAvailable(tokens);
        if (delay <= 0) {
          this.processQueue();
        } else {
          waiter.timer = setTimeout(() => {
            waiter.timer = null;
            this.processQueue();
          }, Math.ceil(delay) + 1);
        }
      }
    });
  }
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function rangeArray(min: number, max: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function parseField(raw: string, field: keyof CronFields): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list — split and recurse
  if (raw.includes(",")) {
    const parts = raw.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), field)) {
        values.add(v);
      }
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  // Step value: */step or start-end/step
  if (raw.includes("/")) {
    const [rangePart, stepStr] = raw.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new TypeError(`Invalid step "${stepStr}" in field "${field}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        rangeMin = parseInt(startStr, 10);
        rangeMax = parseInt(endStr, 10);
        if (isNaN(rangeMin) || isNaN(rangeMax)) {
          throw new TypeError(`Invalid range "${rangePart}" in field "${field}"`);
        }
        assertInRange(rangeMin, min, max, field);
        assertInRange(rangeMax, min, max, field);
        if (rangeMin > rangeMax) {
          throw new RangeError(
            `Range start ${rangeMin} > end ${rangeMax} in field "${field}"`
          );
        }
      } else {
        rangeMin = parseInt(rangePart, 10);
        if (isNaN(rangeMin)) {
          throw new TypeError(`Invalid step base "${rangePart}" in field "${field}"`);
        }
        assertInRange(rangeMin, min, max, field);
        rangeMax = max;
      }
    }

    return rangeArray(rangeMin, rangeMax, step);
  }

  // Range: start-end
  if (raw.includes("-")) {
    const [startStr, endStr] = raw.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new TypeError(`Invalid range "${raw}" in field "${field}"`);
    }
    assertInRange(start, min, max, field);
    assertInRange(end,   min, max, field);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} > end ${end} in field "${field}"`
      );
    }
    return rangeArray(start, end);
  }

  // Wildcard
  if (raw === "*") {
    return rangeArray(min, max);
  }

  // Plain number
  const value = parseInt(raw, 10);
  if (isNaN(value)) {
    throw new TypeError(`Invalid value "${raw}" in field "${field}"`);
  }
  assertInRange(value, min, max, field);
  return [value];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = parts;

  return {
    minute:     parseField(minuteRaw, "minute"),
    hour:       parseField(hourRaw,   "hour"),
    dayOfMonth: parseField(domRaw,    "dayOfMonth"),
    month:      parseField(monthRaw,  "month"),
    dayOfWeek:  parseField(dowRaw,    "dayOfWeek"),
  };
}

/**
 * Converts a subset of Markdown to HTML.
 * Supports: headings, bold, italic, code spans, code blocks,
 * unordered lists, links, and paragraphs.
 */

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function isValidUrl(url: string): boolean {
  if (!url || url.trim().length === 0) return false;
  // Allow relative URLs and common schemes
  if (url.startsWith("/") || url.startsWith("./") || url.startsWith("../") || url.startsWith("#")) {
    return true;
  }
  try {
    const parsed = new URL(url);
    return ["http:", "https:", "mailto:", "ftp:"].includes(parsed.protocol);
  } catch {
    return false;
  }
}

function parseInline(text: string): string {
  if (!text || text.length === 0) return "";

  // Process code spans first (highest precedence, contents not further parsed)
  const codeSpanParts: string[] = [];
  let codeIndex = 0;
  const codeSpanPlaceholderPrefix = "\x00CODE";
  const codeSpanPlaceholderSuffix = "\x00";

  const withCodeSpans = text.replace(/(`+)([\s\S]*?)\1/g, (_match, backticks, content) => {
    const placeholder = `${codeSpanPlaceholderPrefix}${codeIndex}${codeSpanPlaceholderSuffix}`;
    codeSpanParts[codeIndex] = `<code>${escapeHtml(content)}</code>`;
    codeIndex++;
    return placeholder;
  });

  // Process links: [text](url)
  const withLinks = withCodeSpans.replace(
    /\[([^\[\]]*)\]\(([^)]*)\)/g,
    (_match, linkText, url) => {
      const trimmedUrl = (url ?? "").trim();
      if (!isValidUrl(trimmedUrl)) {
        return escapeHtml(`[${linkText}](${url})`);
      }
      const safeUrl = escapeHtml(trimmedUrl);
      const safeText = parseInline(linkText);
      return `<a href="${safeUrl}">${safeText}</a>`;
    }
  );

  // Bold: **text** or __text__ (process before italic)
  const withBold = withLinks.replace(
    /(\*\*|__)(?=\S)([\s\S]*?\S)\1/g,
    (_match, _delim, content) => `<strong>${parseInline(content)}</strong>`
  );

  // Italic: *text* or _text_ (single delimiters, not followed by space)
  const withItalic = withBold.replace(
    /(\*|_)(?=\S)([\s\S]*?\S)\1/g,
    (_match, _delim, content) => `<em>${parseInline(content)}</em>`
  );

  // Restore code spans
  const withRestoredCode = withItalic.replace(
    new RegExp(`${codeSpanPlaceholderPrefix}(\\d+)${codeSpanPlaceholderSuffix}`, "g"),
    (_match, idx) => codeSpanParts[parseInt(idx, 10)] ?? ""
  );

  return withRestoredCode;
}

interface ListItem {
  indent: number;
  content: string;
  children: ListItem[];
}

function buildListHtml(items: ListItem[]): string {
  if (items.length === 0) return "";
  let html = "<ul>\n";
  for (const item of items) {
    if (item.children.length > 0) {
      html += `<li>${parseInline(item.content)}\n${buildListHtml(item.children)}</li>\n`;
    } else {
      html += `<li>${parseInline(item.content)}</li>\n`;
    }
  }
  html += "</ul>";
  return html;
}

function parseListItems(lines: string[]): ListItem[] {
  // Build a flat list of {indent, content} first
  const flat: { indent: number; content: string }[] = [];
  for (const line of lines) {
    const match = line.match(/^(\s*)(?:[-*])\s+(.*)$/);
    if (match) {
      const indent = match[1].length;
      const content = match[2].trim();
      flat.push({ indent, content });
    }
  }

  if (flat.length === 0) return [];

  // Normalize indents relative to the minimum indent
  const minIndent = Math.min(...flat.map((f) => f.indent));
  const normalized = flat.map((f) => ({ ...f, indent: f.indent - minIndent }));

  function buildNested(items: typeof normalized, startIdx: number, parentIndent: number): { items: ListItem[]; nextIdx: number } {
    const result: ListItem[] = [];
    let i = startIdx;

    while (i < items.length) {
      const current = items[i];

      if (current.indent < parentIndent) {
        break;
      }

      if (current.indent === parentIndent) {
        const listItem: ListItem = { indent: current.indent, content: current.content, children: [] };
        i++;

        // Collect children (items with greater indent)
        if (i < items.length && items[i].indent > parentIndent) {
          const childResult = buildNested(items, i, items[i].indent);
          listItem.children = childResult.items;
          i = childResult.nextIdx;
        }

        result.push(listItem);
      } else {
        // Indent is greater than parentIndent but we're not expecting that here
        // Skip to avoid infinite loop
        i++;
      }
    }

    return { items: result, nextIdx: i };
  }

  return buildNested(normalized, 0, 0).items;
}

function isListLine(line: string): boolean {
  return /^\s*[-*]\s+/.test(line);
}

