export interface RateLimiterOptions {
  /** Maximum number of tokens the bucket can hold. */
  maxTokens: number;
  /** Number of tokens added per refill interval. */
  refillRate: number;
  /** Duration in milliseconds between refills. */
  refillIntervalMs: number;
}

interface Waiter {
  readonly tokens: number;
  readonly resolve: () => void;
  readonly reject: (reason: unknown) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Waiter[] = [];
  private pendingTimeout: ReturnType<typeof setTimeout> | null = null;

  constructor(options: RateLimiterOptions) {
    if (options === null || typeof options !== "object") {
      throw new TypeError("RateLimiter: options must be a non-null object");
    }

    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(
        "RateLimiter: maxTokens must be a positive finite number"
      );
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(
        "RateLimiter: refillRate must be a positive finite number"
      );
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(
        "RateLimiter: refillIntervalMs must be a positive finite number"
      );
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  // ---------------------------------------------------------------------------
  // Private helpers
  // ---------------------------------------------------------------------------

  /** Lazily refill tokens based on elapsed wall-clock time. */
  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed >= this.refillIntervalMs) {
      const intervals = Math.floor(elapsed / this.refillIntervalMs);
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + tokensToAdd
      );
      // Advance lastRefillTime by whole intervals only to preserve sub-interval
      // elapsed time for the next call.
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  private validateTokenAmount(tokens: number, caller: string): void {
    if (typeof tokens !== "number" || !Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(
        `${caller}: tokens must be a positive finite number, got ${tokens}`
      );
    }
  }

  /**
   * Returns how many milliseconds from now until at least `tokens` tokens are
   * available.  Assumes `refill()` has already been called.
   */
  private msUntilAvailable(tokens: number): number {
    if (this.currentTokens >= tokens) return 0;

    const deficit = tokens - this.currentTokens;
    const intervalsNeeded = Math.ceil(deficit / this.refillRate);
    const elapsedSinceLastRefill = Date.now() - this.lastRefillTime;
    const msUntilNextRefill =
      this.refillIntervalMs - (elapsedSinceLastRefill % this.refillIntervalMs);

    // First interval fires in `msUntilNextRefill`; each subsequent one after
    // another `refillIntervalMs`.
    return msUntilNextRefill + (intervalsNeeded - 1) * this.refillIntervalMs;
  }

  /** Schedule a single wakeup for the head-of-line waiter. */
  private scheduleWakeup(): void {
    if (this.waiters.length === 0 || this.pendingTimeout !== null) return;

    this.refill();
    const delay = this.msUntilAvailable(this.waiters[0].tokens);

    // Add a 1 ms buffer to avoid waking up just a hair early due to timer
    // imprecision.
    this.pendingTimeout = setTimeout(() => {
      this.pendingTimeout = null;
      this.drainWaiters();
    }, Math.max(0, delay) + 1);
  }

  /** Process as many head-of-line waiters as current tokens allow (FIFO). */
  private drainWaiters(): void {
    if (this.pendingTimeout !== null) {
      clearTimeout(this.pendingTimeout);
      this.pendingTimeout = null;
    }

    while (this.waiters.length > 0) {
      this.refill();
      const waiter = this.waiters[0];

      if (this.currentTokens >= waiter.tokens) {
        this.waiters.shift();
        this.currentTokens -= waiter.tokens;
        waiter.resolve();
      } else {
        // Head-of-line blocking: do not serve out-of-order.
        break;
      }
    }

    if (this.waiters.length > 0) {
      this.scheduleWakeup();
    }
  }

  // ---------------------------------------------------------------------------
  // Public API
  // ---------------------------------------------------------------------------

  /**
   * Attempt to consume `tokens` (default 1) immediately.
   * Returns `true` if the tokens were consumed; `false` otherwise.
   */
  tryConsume(tokens: number = 1): boolean {
    this.validateTokenAmount(tokens, "tryConsume");

    // A request that exceeds maxTokens can never succeed.
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      // Refilling may have freed tokens that queued waiters can now use.
      this.drainWaiters();
      return true;
    }

    return false;
  }

  /**
   * Returns the number of tokens currently available (after lazy refill).
   */
  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  /**
   * Immediately reset the bucket to full capacity and wake any queued waiters.
   */
  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainWaiters();
  }

  /**
   * Returns a Promise that resolves once `tokens` (default 1) have been
   * successfully consumed.  Waiters are served in FIFO order.
   *
   * Rejects immediately if `tokens` exceeds `maxTokens` (the request could
   * never be fulfilled) or if the arguments are invalid.
   */
  waitForTokens(tokens: number = 1): Promise<void> {
    try {
      this.validateTokenAmount(tokens, "waitForTokens");
    } catch (err) {
      return Promise.reject(err);
    }

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `waitForTokens: requested ${tokens} token(s) but bucket capacity is ` +
            `${this.maxTokens}; this request can never be fulfilled`
        )
      );
    }

    this.refill();

    // Fast path: no one is waiting and there are enough tokens right now.
    if (this.waiters.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    // Slow path: queue this request and schedule a wakeup.
    return new Promise<void>((resolve, reject) => {
      const waiter: Waiter = { tokens, resolve, reject };
      this.waiters.push(waiter);
      // Only schedule if this is the new head-of-line (i.e. no pending timer).
      this.scheduleWakeup();
    });
  }
}

export default RateLimiter;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = {
  name: keyof CronFields;
  min: number;
  max: number;
};

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 7 },
] as const;

function isValidInteger(value: string): boolean {
  return /^\d+$/.test(value.trim());
}

function parseInteger(value: string, fieldName: string): number {
  const trimmed = value.trim();
  if (!isValidInteger(trimmed)) {
    throw new Error(
      `Invalid value "${trimmed}" in field "${fieldName}": must be a non-negative integer`
    );
  }
  const parsed = parseInt(trimmed, 10);
  if (!Number.isFinite(parsed)) {
    throw new Error(`Invalid integer "${trimmed}" in field "${fieldName}"`);
  }
  return parsed;
}

function clampAndValidate(
  value: number,
  min: number,
  max: number,
  fieldName: string
): number {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of range [${min}, ${max}] for field "${fieldName}"`
    );
  }
  return value;
}

function deduplicateAndSort(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function expandRange(
  start: number,
  end: number,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const validStart = clampAndValidate(start, min, max, fieldName);
  const validEnd = clampAndValidate(end, min, max, fieldName);

  if (validStart > validEnd) {
    throw new Error(
      `Invalid range "${start}-${end}" in field "${fieldName}": start must be <= end`
    );
  }

  const result: number[] = [];
  for (let i = validStart; i <= validEnd; i++) {
    result.push(i);
  }
  return result;
}

function parseSegment(
  segment: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new Error(`Empty segment found in field "${fieldName}"`);
  }

  // Wildcard: "*"
  if (trimmed === "*") {
    const result: number[] = [];
    for (let i = min; i <= max; i++) {
      result.push(i);
    }
    return result;
  }

  // Step value: "*/N" or "M-N/S" or "M/N"
  if (trimmed.includes("/")) {
    const slashIndex = trimmed.lastIndexOf("/");
    const basePart = trimmed.substring(0, slashIndex);
    const stepPart = trimmed.substring(slashIndex + 1);

    if (basePart === "" || stepPart === "") {
      throw new Error(
        `Invalid step expression "${trimmed}" in field "${fieldName}"`
      );
    }

    const step = parseInteger(stepPart, fieldName);
    if (step <= 0) {
      throw new Error(
        `Step value must be >= 1 in field "${fieldName}", got ${step}`
      );
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (basePart === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (basePart.includes("-")) {
      const dashIndex = basePart.indexOf("-");
      const startStr = basePart.substring(0, dashIndex);
      const endStr = basePart.substring(dashIndex + 1);
      rangeStart = clampAndValidate(
        parseInteger(startStr, fieldName),
        min,
        max,
        fieldName
      );
      rangeEnd = clampAndValidate(
        parseInteger(endStr, fieldName),
        min,
        max,
        fieldName
      );
      if (rangeStart > rangeEnd) {
        throw new Error(
          `Invalid range "${basePart}" in field "${fieldName}": start must be <= end`
        );
      }
    } else {
      rangeStart = clampAndValidate(
        parseInteger(basePart, fieldName),
        min,
        max,
        fieldName
      );
      rangeEnd = max;
    }

    const result: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      result.push(i);
    }
    return result;
  }

  // Range: "M-N"
  if (trimmed.includes("-")) {
    const dashIndex = trimmed.indexOf("-");
    const startStr = trimmed.substring(0, dashIndex);
    const endStr = trimmed.substring(dashIndex + 1);

    if (startStr === "" || endStr === "") {
      throw new Error(
        `Invalid range expression "${trimmed}" in field "${fieldName}"`
      );
    }

    const start = parseInteger(startStr, fieldName);
    const end = parseInteger(endStr, fieldName);
    return expandRange(start, end, min, max, fieldName);
  }

  // Single number
  const value = parseInteger(trimmed, fieldName);
  clampAndValidate(value, min, max, fieldName);
  return [value];
}

function parseField(
  raw: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  if (typeof raw !== "string" || raw.trim() === "") {
    throw new Error(`Missing or empty field "${fieldName}"`);
  }

  const trimmed = raw.trim();
  const segments = trimmed.split(",");

  if (segments.length === 0) {
    throw new Error(`No segments found in field "${fieldName}"`);
  }

  const allValues: number[] = [];

  for (const segment of segments) {
    const values = parseSegment(segment, min, max, fieldName);
    allValues.push(...values);
  }

  const result = deduplicateAndSort(allValues);

  // Normalize dayOfWeek: treat 7 as Sunday (0)
  if (fieldName === "dayOfWeek") {
    return deduplicateAndSort(result.map((v) => (v === 7 ? 0 : v)));
  }

  return result;
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  // Normalize internal whitespace to single spaces
  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${trimmed}"`
    );
  }

  const result: Partial<CronFields> = {};

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    result[config.name] = parseField(
      parts[i],
      config.min,
      config.max,
      config.name
    );
  }

  return result as CronFields;
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function processInline(text: string): string {
  const codeSpans: string[] = [];

  // 1. Extract code spans first — protect their content from all further processing
  text = text.replace(/`([^`]+)`/g, (_, code) => {
    const idx = codeSpans.length;
    codeSpans.push(`<code>${escapeHtml(code)}</code>`);
    // \x00 is not an HTML special char, so it survives escapeHtml below
    return `\x00${idx}\x00`;
  });

  // 2. Escape HTML in remaining text
  text = escapeHtml(text);

  // 3. Links — [text](url) — brackets/parens are not escaped by escapeHtml
  text = text.replace(/\[([^\]]*)\]\(([^)]*)\)/g, (_, linkText, url) => {
    return `<a href="${url}">${linkText}</a>`;
  });

  // 4. Bold before italic — must handle ** before * to avoid partial matches
  text = text.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");
  // Use word-boundary guards on __ to prevent mangling identifiers like my__var
  text = text.replace(/(?<!\w)__(.+?)__(?!\w)/g, "<strong>$1</strong>");

  // 5. Italic
  text = text.replace(/\*(.+?)\*/g, "<em>$1</em>");
  // Guard _ with boundary checks to avoid mangling foo_bar_baz
  text = text.replace(/(?<!\w)_(.+?)_(?!\w)/g, "<em>$1</em>");

  // 6. Restore extracted code spans
  text = text.replace(/\x00(\d+)\x00/g, (_, idx) => codeSpans[parseInt(idx, 10)]);

  return text;
}

