    if (nestedLines.length > 0) {
      parts.push(`<li>${processInline(content)}\n${buildList(nestedLines)}</li>`);
    } else {
      parts.push(`<li>${processInline(content)}</li>`);
    }
  }

  parts.push("</ul>");
  return parts.join("\n");
}

