  readonly tokens: number;
  readonly resolve: () => void;
  readonly reject: (err: Error) => void;
};

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Waiter[];
  private timer: ReturnType<typeof setTimeout> | null;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a non-negative finite number");
    }
    if (
      !Number.isFinite(options.refillIntervalMs) ||
      options.refillIntervalMs <= 0
    ) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waiters = [];
    this.timer = null;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed < this.refillIntervalMs) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    const added = intervals * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
    // Advance lastRefillTime by whole intervals only, preserving sub-interval remainder
    this.lastRefillTime += intervals * this.refillIntervalMs;
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    if (tokens === 0) return true;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    if (this.timer !== null) {
      clearTimeout(this.timer);
      this.timer = null;
    }
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.processWaiters();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError("tokens must be a non-negative finite number")
      );
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; ` +
            `this can never be satisfied`
        )
      );
    }

    this.refill();

    // Fast path: no queued waiters and sufficient tokens available right now
    if (this.waiters.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    // Detect permanently unsatisfiable waits when refillRate is zero
    if (this.refillRate === 0 && this.currentTokens < tokens) {
      return Promise.reject(
        new Error(
          `Cannot satisfy waitForTokens(${tokens}): only ${this.currentTokens} token(s) ` +
            `available and refillRate is 0`
        )
      );
    }

    return new Promise<void>((resolve, reject) => {
      this.waiters.push({ tokens, resolve, reject });
      this.scheduleTimer();
    });
  }

  private processWaiters(): void {
    this.refill();

    // Drain the queue front-to-back (FIFO fairness): a waiter only gets tokens
    // once every waiter ahead of it has been satisfied.
    while (this.waiters.length > 0) {
      const waiter = this.waiters[0];
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waiters.shift();
        // Resolve outside of the loop to avoid reentrancy surprises
        waiter.resolve();
      } else {
        break;
      }
    }

    if (this.waiters.length > 0) {
      this.scheduleTimer();
    }
  }

  private scheduleTimer(): void {
    // Only one pending timer at a time; it re-schedules itself if needed.
    if (this.timer !== null) return;
    if (this.waiters.length === 0) return;

    const nextWaiter = this.waiters[0];
    const tokensNeeded = nextWaiter.tokens - this.currentTokens;

    if (tokensNeeded <= 0) {
      // Should have been consumed in processWaiters — schedule an immediate
      // microtask as a safety valve rather than spinning synchronously.
      this.timer = setTimeout(() => {
        this.timer = null;
        this.processWaiters();
      }, 0);
      return;
    }

    // Guard: refillRate of 0 with insufficient tokens is unsatisfiable.
    // This branch is a backstop; the public API rejects such requests eagerly.
    if (this.refillRate <= 0) {
      const waiter = this.waiters.shift()!;
      waiter.reject(
        new Error(
          `Cannot satisfy waitForTokens(${waiter.tokens}): refillRate is 0 ` +
            `and insufficient tokens remain`
        )
      );
      this.processWaiters();
      return;
    }

    // Calculate the earliest moment currentTokens can reach nextWaiter.tokens.
    // After refill(), lastRefillTime is pegged to the last whole interval boundary,
    // so timeUntilNextRefill is always in (0, refillIntervalMs].
    const timeUntilNextRefill =
      this.refillIntervalMs - (Date.now() - this.lastRefillTime);
    const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
    const delay = Math.max(
      0,
      timeUntilNextRefill + (intervalsNeeded - 1) * this.refillIntervalMs
    );

    this.timer = setTimeout(() => {
      this.timer = null;
      this.processWaiters();
    }, delay);
  }
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private scheduleHandle: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (options == null || typeof options !== "object") {
      throw new TypeError("RateLimiter: options must be a non-null object");
    }

    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(
        `RateLimiter: maxTokens must be a positive finite number, got ${maxTokens}`
      );
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(
        `RateLimiter: refillRate must be a positive finite number, got ${refillRate}`
      );
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(
        `RateLimiter: refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`
      );
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduleHandle = null;
  }

  /**
   * Lazily refills tokens based on how many complete refill intervals have
   * elapsed since the last refill. Advances lastRefillTime by whole intervals
   * only, preserving the partial interval for accurate future refills.
   */
  private refill(): void {
    const now = Date.now();
    const elapsedMs = now - this.lastRefillTime;

    if (elapsedMs <= 0) return;

    const intervalsElapsed = Math.floor(elapsedMs / this.refillIntervalMs);
    if (intervalsElapsed > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervalsElapsed * this.refillRate
      );
      // Advance only by complete intervals to preserve the partial interval
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  private validateTokens(tokens: number, method: string): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(
        `${method}: tokens must be a non-negative finite number, got ${tokens}`
      );
    }
  }

  /**
   * Drains the wait queue, resolving waiters in FIFO order as tokens permit.
   * Schedules a future check if waiters remain.
   */
  private processWaiters(): void {
    this.refill();

    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0]!;
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        // First waiter cannot be served yet; stop to preserve ordering
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextCheck();
    }
  }

  /**
   * Computes the earliest time the first waiter's request can be satisfied
   * and schedules a setTimeout to process it. Guards against double-scheduling.
   */
  private scheduleNextCheck(): void {
    if (this.scheduleHandle !== null) return;

    const waiter = this.waitQueue[0];
    if (waiter == null) return;

    // ms elapsed in the current (partial) refill interval
    const partialElapsed = Date.now() - this.lastRefillTime;
    const timeUntilNextRefill = Math.max(
      0,
      this.refillIntervalMs - partialElapsed
    );

    const tokensNeeded = waiter.tokens - this.currentTokens;
    // Number of full refill intervals required to accumulate enough tokens
    const intervalsRequired = Math.ceil(tokensNeeded / this.refillRate);

    // First interval fires in timeUntilNextRefill; subsequent ones every refillIntervalMs
    const delay =
      timeUntilNextRefill + (intervalsRequired - 1) * this.refillIntervalMs;

    this.scheduleHandle = setTimeout(() => {
      this.scheduleHandle = null;
      this.processWaiters();
    }, Math.max(1, Math.ceil(delay)));
  }

  /**
   * Attempts to consume the given number of tokens immediately.
   * Returns true if the tokens were consumed, false if insufficient tokens.
   */
  tryConsume(tokens: number = 1): boolean {
    this.validateTokens(tokens, "tryConsume");

    if (tokens === 0) return true;
    // A request exceeding maxTokens can never succeed
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  /**
   * Returns the current number of available tokens after a lazy refill.
   */
  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  /**
   * Resets the bucket to full capacity and clears the refill clock.
   * Pending waitForTokens callers are re-evaluated immediately.
   */
  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    // Cancel any pending schedule so processWaiters can reschedule accurately
    if (this.scheduleHandle !== null) {
      clearTimeout(this.scheduleHandle);
      this.scheduleHandle = null;
    }

    this.processWaiters();
  }

  /**
   * Waits asynchronously until the given number of tokens are available,
   * then atomically consumes them. Waiters are served in FIFO order.
   *
   * Throws RangeError immediately if tokens > maxTokens (would never resolve).
   */
  async waitForTokens(tokens: number = 1): Promise<void> {
    this.validateTokens(tokens, "waitForTokens");

    if (tokens === 0) return;

    if (tokens > this.maxTokens) {
      throw new RangeError(
        `waitForTokens: requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); ` +
          `this request can never be fulfilled`
      );
    }

    // Fast path: no queue backlog and sufficient tokens available right now
    if (this.waitQueue.length === 0) {
      this.refill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return;
      }
    }

    // Slow path: enqueue and wait
    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      // Only schedule if nothing is already scheduled
      if (this.scheduleHandle === null) {
        this.scheduleNextCheck();
      }
    });
  }
}

