export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

const FIELD_ORDER: (keyof CronFields)[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function isInteger(value: string): boolean {
  return /^-?\d+$/.test(value.trim());
}

function parseNumber(value: string, fieldName: keyof CronFields): number {
  if (!isInteger(value)) {
    throw new Error(
      `Invalid value "${value}" in field "${fieldName}": must be an integer`
    );
  }
  const num = parseInt(value, 10);
  const { min, max } = FIELD_CONFIGS[fieldName];
  if (num < min || num > max) {
    throw new Error(
      `Value ${num} out of range [${min}, ${max}] for field "${fieldName}"`
    );
  }
  return num;
}

function expandWildcard(fieldName: keyof CronFields): number[] {
  const { min, max } = FIELD_CONFIGS[fieldName];
  return Array.from({ length: max - min + 1 }, (_, i) => i + min);
}

function expandStep(token: string, fieldName: keyof CronFields): number[] {
  const [baseStr, stepStr] = token.split("/");

  if (!isInteger(stepStr) || parseInt(stepStr, 10) <= 0) {
    throw new Error(
      `Invalid step value "${stepStr}" in field "${fieldName}": must be a positive integer`
    );
  }

  const step = parseInt(stepStr, 10);
  const { min, max } = FIELD_CONFIGS[fieldName];

  let rangeMin: number;
  let rangeMax: number;

  if (baseStr === "*") {
    rangeMin = min;
    rangeMax = max;
  } else if (baseStr.includes("-")) {
    const [rangeMinStr, rangeMaxStr] = baseStr.split("-");
    rangeMin = parseNumber(rangeMinStr, fieldName);
    rangeMax = parseNumber(rangeMaxStr, fieldName);
    if (rangeMin > rangeMax) {
      throw new Error(
        `Invalid range "${baseStr}" in field "${fieldName}": start must be <= end`
      );
    }
  } else {
    rangeMin = parseNumber(baseStr, fieldName);
    rangeMax = max;
  }

  const values: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) {
    values.push(i);
  }
  return values;
}

function expandRange(token: string, fieldName: keyof CronFields): number[] {
  const parts = token.split("-");
  if (parts.length !== 2) {
    throw new Error(
      `Invalid range "${token}" in field "${fieldName}": expected exactly one "-"`
    );
  }
  const start = parseNumber(parts[0], fieldName);
  const end = parseNumber(parts[1], fieldName);
  if (start > end) {
    throw new Error(
      `Invalid range "${token}" in field "${fieldName}": start must be <= end`
    );
  }
  return Array.from({ length: end - start + 1 }, (_, i) => i + start);
}

function parseToken(token: string, fieldName: keyof CronFields): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new Error(`Empty token in field "${fieldName}"`);
  }

  if (trimmed === "*") {
    return expandWildcard(fieldName);
  }

  if (trimmed.includes("/")) {
    return expandStep(trimmed, fieldName);
  }

  if (trimmed.includes("-")) {
    return expandRange(trimmed, fieldName);
  }

  return [parseNumber(trimmed, fieldName)];
}

function parseField(expression: string, fieldName: keyof CronFields): number[] {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error(`Empty or invalid expression for field "${fieldName}"`);
  }

  const tokens = expression.split(",");
  const valueSet = new Set<number>();

  for (const token of tokens) {
    const values = parseToken(token, fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  // Normalize dayOfWeek: treat 7 as Sunday (same as 0)
  if (fieldName === "dayOfWeek" && valueSet.has(7)) {
    valueSet.delete(7);
    valueSet.add(0);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(fields[i], fieldName);
  }

  return result;
}

