/**
 * Processes inline Markdown elements within a run of text.
 * Code spans are extracted first so their contents are never processed.
 * HTML is escaped before applying bold/italic so special chars stay safe.
 *
 * @param text  - raw Markdown inline text
 * @param depth - recursion guard (links may contain bold/italic/code)
 */
function processInline(text: string, depth = 0): string {
  if (!text) return "";
  if (depth > 10) return escapeHtml(text); // safety guard against deep nesting

  const slots: string[] = [];

  /** Replace a span with a placeholder so it survives further processing. */
  const protect = (html: string): string => {
    const idx = slots.length;
    slots.push(html);
    return `\x00P${idx}\x00`;
  };

  /** Restore all protected placeholders at the end. */
  const restore = (s: string): string =>
    s.replace(/\x00P(\d+)\x00/g, (_, i) => slots[parseInt(i, 10)] ?? "");

  // 1. Code spans — protect raw content so it is never further processed
  text = text.replace(/`([^`]*)`/g, (_, code) =>
    protect(`<code>${escapeHtml(code)}</code>`)
  );

  // 2. Links — only parse at depth 0 to prevent nested link syntax
  if (depth === 0) {
    text = text.replace(/\[([^\]]*)\]\(([^)]*)\)/g, (_, linkText, rawUrl) => {
      const href = sanitizeUrl(rawUrl);
      const inner = processInline(linkText, depth + 1);
      return protect(`<a href="${href}">${inner}</a>`);
    });
  }

  // 3. Escape HTML entities in remaining plain-text portions
  text = escapeHtml(text);

  // 4. Bold — ** or __ (non-greedy; __ requires non-word boundary to avoid
  //    matching underscores inside identifiers like `some_var_name`)
  text = text.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");
  text = text.replace(/(?<!\w)__(.+?)__(?!\w)/g, "<strong>$1</strong>");

  // 5. Italic — * or _ (must not be adjacent to another * or _, respectively)
  text = text.replace(
    /(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g,
    "<em>$1</em>"
  );
  text = text.replace(
    /(?<!\w)_(?!_)(.+?)(?<!_)_(?!\w)/g,
    "<em>$1</em>"
  );

  // 6. Restore all protected spans
  return restore(text);
}

