function parseListItems(lines: string[]): ListItem[] {
  const items: ListItem[] = [];
  for (const line of lines) {
    const m = line.match(/^([ \t]*)([-*+])\s+(.*)$/);
    if (m) {
      let indent = 0;
      for (const ch of m[1]) indent += ch === "\t" ? 4 : 1;
      items.push({ indent, content: m[3] });
    } else if (items.length > 0 && line.trim() !== "") {
      // Continuation line — append to the last item
      items[items.length - 1].content += " " + line.trim();
    }
  }
  return items;
}

/**
 * Recursively render a slice of list items at a given nesting depth.
 * Items whose indent is ≤ parentIndent belong to a higher level and cause
 * the recursive call to return.
 */
function renderListLevel(
  items: ListItem[],
  start: number,
  parentIndent: number
): { html: string; end: number } {
  let html = "";
  let i = start;

  while (i < items.length && items[i].indent > parentIndent) {
    const cur = items[i];
    const curIndent = cur.indent;
    i++;

    let liContent = processInline(cur.content);

    // If the next item is deeper, render it as a nested <ul>
    if (i < items.length && items[i].indent > curIndent) {
      const sub = renderListLevel(items, i, curIndent);
      liContent += `\n<ul>${sub.html}</ul>`;
      i = sub.end;
    }

    html += `<li>${liContent}</li>`;
  }

  return { html, end: i };
}

function buildListHtml(lines: string[]): string {
  const items = parseListItems(lines);
  if (items.length === 0) return "";
  const { html } = renderListLevel(items, 0, -1);
  return `<ul>${html}</ul>`;
}

