  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Record<FieldName, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 7 = Sunday alias, same as 0
} as const;

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const INTEGER_RE = /^\d+$/;

function assertInteger(raw: string, context: string): number {
  if (!INTEGER_RE.test(raw)) {
    throw new Error(`Invalid integer "${raw}" in ${context}`);
  }
  return parseInt(raw, 10);
}

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of range [${config.min}–${config.max}] in ${context}`
    );
  }
}

function range(start: number, end: number, step: number = 1): number[] {
  if (step <= 0) throw new Error(`Step must be a positive integer, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, config: FieldConfig, context: string): number[] {
  if (!segment) {
    throw new Error(`Empty segment in ${context}`);
  }

  // Step expression: <base>/<step>
  if (segment.includes("/")) {
    const slashCount = (segment.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new Error(`Multiple "/" in segment "${segment}" in ${context}`);
    }

    const [basePart, stepPart] = segment.split("/");
    const step = assertInteger(stepPart, `${context} step`);
    if (step === 0) {
      throw new Error(`Step value cannot be zero in ${context}`);
    }

    let start: number;
    let end: number;

    if (basePart === "*") {
      start = config.min;
      end   = config.max;
    } else if (basePart.includes("-")) {
      [start, end] = parseRange(basePart, config, context);
    } else {
      start = assertInteger(basePart, `${context} step base`);
      assertInRange(start, config, context);
      end = config.max;
    }

    if (start > end) {
      throw new RangeError(`Start ${start} > end ${end} in ${context}`);
    }

    return range(start, end, step);
  }

  // Wildcard
  if (segment === "*") {
    return range(config.min, config.max);
  }

  // Range: N-M
  if (segment.includes("-")) {
    const [start, end] = parseRange(segment, config, context);
    return range(start, end);
  }

  // Single integer
  const value = assertInteger(segment, context);
  assertInRange(value, config, context);
  return [value];
}

function parseRange(segment: string, config: FieldConfig, context: string): [number, number] {
  const dashCount = (segment.match(/-/g) ?? []).length;
  if (dashCount !== 1) {
    throw new Error(`Invalid range "${segment}" in ${context}`);
  }
  const [startStr, endStr] = segment.split("-");
  const start = assertInteger(startStr, `${context} range start`);
  const end   = assertInteger(endStr,   `${context} range end`);
  assertInRange(start, config, context);
  assertInRange(end,   config, context);
  if (start > end) {
    throw new RangeError(
      `Range start ${start} > end ${end} in ${context}`
    );
  }
  return [start, end];
}

function parseField(raw: string, config: FieldConfig, fieldName: FieldName): number[] {
  if (!raw) {
    throw new Error(`Field "${fieldName}" is empty`);
  }

  const context = `field "${fieldName}"`;

  // Comma-separated list
  const parts = raw.split(",");
  const valueSet = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) {
      throw new Error(`Empty value in comma list for ${context}`);
    }
    const values = parseSegment(trimmed, config, context);
    for (const v of values) {
      valueSet.add(v);
