interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Readonly<Record<keyof CronExpression, FieldConfig>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 7 = Sunday alias for 0
} as const;

function assertIntInRange(
  value: number,
  config: FieldConfig,
  fieldName: string,
  context: string,
): void {
  if (!Number.isInteger(value)) {
    throw new RangeError(
      `Field "${fieldName}": non-integer value ${value} in "${context}"`,
    );
  }
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Field "${fieldName}": value ${value} out of valid range ` +
      `[${config.min}, ${config.max}] in "${context}"`,
    );
  }
}

function parseIntStrict(raw: string, fieldName: string, context: string): number {
  // Reject leading zeros (e.g. "09") and non-numeric characters
  if (!/^-?\d+$/.test(raw)) {
    throw new TypeError(
      `Field "${fieldName}": expected integer, got "${raw}" in "${context}"`,
    );
  }
  return parseInt(raw, 10);
}

function expandStep(
  start: number,
  end: number,
  step: number,
  config: FieldConfig,
  fieldName: string,
  context: string,
): number[] {
  assertIntInRange(start, config, fieldName, context);
  assertIntInRange(end, config, fieldName, context);

  if (start > end) {
    throw new RangeError(
      `Field "${fieldName}": range start ${start} > end ${end} in "${context}"`,
    );
  }
  if (step <= 0) {
    throw new RangeError(
      `Field "${fieldName}": step must be positive, got ${step} in "${context}"`,
    );
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(
  segment: string,
  config: FieldConfig,
  fieldName: string,
): number[] {
  if (segment === '') {
    throw new SyntaxError(`Field "${fieldName}": empty segment`);
  }

  // Step expression: <range-or-wildcard>/<step>
  const slashIdx = segment.indexOf('/');
  if (slashIdx !== -1) {
    const left  = segment.slice(0, slashIdx);
    const right = segment.slice(slashIdx + 1);

    if (right === '' || right.includes('/')) {
      throw new SyntaxError(
        `Field "${fieldName}": invalid step expression "${segment}"`,
      );
    }

    const step = parseIntStrict(right, fieldName, segment);

    if (left === '*') {
      return expandStep(config.min, config.max, step, config, fieldName, segment);
    }

    const dashIdx = left.indexOf('-');
    if (dashIdx !== -1) {
      const start = parseIntStrict(left.slice(0, dashIdx), fieldName, segment);
      const end   = parseIntStrict(left.slice(dashIdx + 1), fieldName, segment);
      return expandStep(start, end, step, config, fieldName, segment);
    }

    // Single number base: N/step  → from N to max
    const base = parseIntStrict(left, fieldName, segment);
    return expandStep(base, config.max, step, config, fieldName, segment);
  }

  // Wildcard
  if (segment === '*') {
    return expandStep(config.min, config.max, 1, config, fieldName, segment);
  }

  // Range: <start>-<end>
  const dashIdx = segment.indexOf('-');
  if (dashIdx !== -1) {
    // Guard against negative numbers masquerading as ranges (e.g. "-5")
    if (dashIdx === 0) {
      throw new SyntaxError(
        `Field "${fieldName}": unexpected leading dash in "${segment}"`,
      );
    }
    const start = parseIntStrict(segment.slice(0, dashIdx), fieldName, segment);
    const end   = parseIntStrict(segment.slice(dashIdx + 1), fieldName, segment);
    return expandStep(start, end, 1, config, fieldName, segment);
  }

  // Single number
  const value = parseIntStrict(segment, fieldName, segment);
  assertIntInRange(value, config, fieldName, segment);
  return [value];
}

function parseField(
  field: string,
  config: FieldConfig,
  fieldName: string,
): number[] {
  if (field === '' || field.trim() === '') {
    throw new SyntaxError(`Field "${fieldName}" is empty`);
  }

  const segments = field.split(',');
  if (segments.some((s) => s === '')) {
    throw new SyntaxError(
      `Field "${fieldName}": trailing or consecutive commas in "${field}"`,
    );
  }

  const seen = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), config, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

