function parseSegment(segment: string, min: number, max: number): number[] {
  // Guard: reject empty segments that could arise from malformed input
  if (!segment || segment.trim() === "") {
    throw new SyntaxError(`Empty segment is not a valid cron field token`);
  }

  const trimmed = segment.trim();

  // Step expression: */n  or  a/n  or  a-b/n
