    const slashParts = trimmed.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Invalid step expression: "${trimmed}"`);
    }

    const [rangePart, stepRaw] = slashParts;
    const step = Number(stepRaw);

    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(
        `Step value must be a positive integer, got "${stepRaw}" in "${trimmed}"`
      );
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (rangePart === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (rangePart.includes("-")) {
      const bounds = rangePart.split("-");
      if (bounds.length !== 2) {
        throw new SyntaxError(`Invalid range in step expression: "${trimmed}"`);
      }
      rangeStart = Number(bounds[0]);
      rangeEnd = Number(bounds[1]);
      if (!Number.isInteger(rangeStart) || !Number.isInteger(rangeEnd)) {
        throw new SyntaxError(`Non-integer bounds in step expression: "${trimmed}"`);
      }
      if (rangeStart > rangeEnd) {
        throw new RangeError(
          `Range start ${rangeStart} exceeds end ${rangeEnd} in "${trimmed}"`
        );
      }
      assertInBounds(rangeStart, min, max, trimmed);
      assertInBounds(rangeEnd, min, max, trimmed);
    } else {
      rangeStart = Number(rangePart);
      if (!Number.isInteger(rangeStart)) {
        throw new SyntaxError(`Non-integer start in step expression: "${trimmed}"`);
      }
      assertInBounds(rangeStart, min, max, trimmed);
      rangeEnd = max;
    }

    const values: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      values.push(i);
