  if (trimmed.includes("-")) {
    const parts = trimmed.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range expression: "${trimmed}"`);
    }
    const start = Number(parts[0]);
    const end = Number(parts[1]);
    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new SyntaxError(`Non-integer bounds in range: "${trimmed}"`);
    }
    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in "${trimmed}"`
      );
    }
    assertInBounds(start, min, max, trimmed);
    assertInBounds(end, min, max, trimmed);
    return buildRange(start, end);
  }

  // Single number
  const num = Number(trimmed);
  if (!Number.isInteger(num)) {
    throw new SyntaxError(`Invalid cron field token: "${trimmed}"`);
  }
  assertInBounds(num, min, max, trimmed);
  return [num];
