  // Comma-separated list — parse each part recursively and flatten
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), fieldName));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step value: */step or start/step or range/step
  if (expr.includes("/")) {
    const [base, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }

    let from: number;
    let to: number;

    if (base === "*") {
      from = min;
      to = max;
    } else if (base.includes("-")) {
      const [rangeFrom, rangeTo] = base.split("-").map((n) => parseInt(n, 10));
      assertInRange(rangeFrom, min, max, fieldName);
      assertInRange(rangeTo, min, max, fieldName);
      from = rangeFrom;
      to = rangeTo;
    } else {
      from = parseInt(base, 10);
      if (isNaN(from)) throw new Error(`Invalid base "${base}" in field "${fieldName}"`);
      assertInRange(from, min, max, fieldName);
      to = max;
    }

    const result: number[] = [];
    for (let v = from; v <= to; v += step) {
      result.push(v);
    }
    return result;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const parts = expr.split("-");
    if (parts.length !== 2) throw new Error(`Invalid range expression "${expr}" in field "${fieldName}"`);
    const from = parseInt(parts[0], 10);
    const to = parseInt(parts[1], 10);
    if (isNaN(from) || isNaN(to)) throw new Error(`Invalid range "${expr}" in field "${fieldName}"`);
    assertInRange(from, min, max, fieldName);
    assertInRange(to, min, max, fieldName);
    return range(from, to);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid value "${expr}" in field "${fieldName}"`);
  assertInRange(value, min, max, fieldName);
  return [value];
}

