function expandRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^-?\d+$/.test(trimmed)) {
    throw new Error(`Expected an integer for ${context}, got: "${raw}"`);
  }
  return parseInt(trimmed, 10);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} is out of valid range [${min}, ${max}] for ${context}`);
  }
}

function parseBaseRange(expr: string, min: number, max: number, context: string): number[] {
  if (expr === "*") return expandRange(min, max);

  if (expr.includes("-")) {
    const parts = expr.split("-");
    if (parts.length !== 2) {
      throw new Error(`Invalid range expression "${expr}" in ${context} — expected exactly one dash`);
    }
    const start = parseInteger(parts[0], `${context} range start`);
    const end   = parseInteger(parts[1], `${context} range end`);
    assertInRange(start, min, max, `${context} range start`);
    assertInRange(end,   min, max, `${context} range end`);
    if (start > end) {
      throw new Error(`Range start ${start} exceeds range end ${end} in ${context}`);
    }
    return expandRange(start, end);
  }

  const num = parseInteger(expr, context);
  assertInRange(num, min, max, context);
  return [num];
}

function parseSingleTerm(expr: string, min: number, max: number, context: string): number[] {
  if (expr.includes("/")) {
    const slashParts = expr.split("/");
    if (slashParts.length !== 2) {
      throw new Error(`Invalid step expression "${expr}" in ${context} — expected exactly one slash`);
    }
    const [rangePart, stepStr] = slashParts;
    const step = parseInteger(stepStr, `${context} step`);
    if (step <= 0) {
      throw new Error(`Step value must be positive, got ${step} in ${context}`);
    }

    // For a plain number with a step (e.g. "5/15"), treat it as "start..max / step"
    let baseValues: number[];
    if (rangePart === "*") {
      baseValues = expandRange(min, max);
    } else if (rangePart.includes("-")) {
      baseValues = parseBaseRange(rangePart, min, max, `${context} step-range`);
    } else {
      const start = parseInteger(rangePart, `${context} step start`);
      assertInRange(start, min, max, `${context} step start`);
      baseValues = expandRange(start, max);
    }

    return baseValues.filter((_, i) => i % step === 0);
  }

  return parseBaseRange(expr, min, max, context);
}

function parseField(expr: string, min: number, max: number, fieldName: string): number[] {
  if (!expr || expr.trim() === "") {
    throw new Error(`Field "${fieldName}" is empty`);
  }

  const trimmed = expr.trim();

  if (trimmed.includes(",")) {
    const seen = new Set<number>();
    const terms = trimmed.split(",");

    for (const term of terms) {
      const trimmedTerm = term.trim();
      if (trimmedTerm === "") {
        throw new Error(`Empty term in comma-separated list for field "${fieldName}"`);
      }
      // Commas cannot be nested — reject slashes and dashes inside list items
      // that themselves contain commas (already split, so safe to recurse)
      const values = parseSingleTerm(trimmedTerm, min, max, fieldName);
      for (const v of values) seen.add(v);
    }

    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSingleTerm(trimmed, min, max, fieldName);
}

