  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in "${context}"`
    );
  }
}

function parseStep(expr: string, config: FieldConfig): number[] {
  const slashIndex = expr.indexOf("/");
  const rangeExpr = expr.slice(0, slashIndex);
  const stepStr = expr.slice(slashIndex + 1);

  if (stepStr.includes("/")) {
    throw new SyntaxError(`Multiple step operators are not allowed in "${expr}"`);
  }

  const step = Number(stepStr);
  if (!Number.isInteger(step) || step <= 0) {
    throw new RangeError(`Step value must be a positive integer, got "${stepStr}" in "${expr}"`);
  }

  let start: number;
  let end: number;

  if (rangeExpr === "*") {
    start = config.min;
    end = config.max;
  } else if (rangeExpr.includes("-")) {
    [start, end] = parseRangeBounds(rangeExpr, config);
  } else {
    const parsed = Number(rangeExpr);
    if (!Number.isInteger(parsed)) {
      throw new SyntaxError(`Invalid start value "${rangeExpr}" in step expression "${expr}"`);
    }
    assertInRange(parsed, config.min, config.max, expr);
    start = parsed;
    end = config.max;
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseRangeBounds(expr: string, config: FieldConfig): [number, number] {
  const dashIndex = expr.indexOf("-");
  if (dashIndex === -1 || dashIndex === 0 || dashIndex === expr.length - 1) {
    throw new SyntaxError(`Invalid range expression "${expr}"`);
  }

  const startStr = expr.slice(0, dashIndex);
  const endStr = expr.slice(dashIndex + 1);

  if (endStr.includes("-")) {
    throw new SyntaxError(`Multiple dash operators in range "${expr}" — only one range bound is allowed`);
  }

  const start = Number(startStr);
  const end = Number(endStr);

  if (!Number.isInteger(start)) {
    throw new SyntaxError(`Invalid range start "${startStr}" in "${expr}"`);
  }
  if (!Number.isInteger(end)) {
    throw new SyntaxError(`Invalid range end "${endStr}" in "${expr}"`);
  }

  assertInRange(start, config.min, config.max, expr);
  assertInRange(end, config.min, config.max, expr);

  if (start > end) {
    throw new RangeError(`Range start ${start} must not exceed range end ${end} in "${expr}"`);
  }

  return [start, end];
}

function parseRange(expr: string, config: FieldConfig): number[] {
  const [start, end] = parseRangeBounds(expr, config);
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function parseSingleField(expr: string, config: FieldConfig): number[] {
  if (expr.length === 0) {
    throw new SyntaxError("Empty field expression is not allowed");
  }

  // Wildcard
  if (expr === "*") {
    const values: number[] = [];
    for (let i = config.min; i <= config.max; i++) {
      values.push(i);
    }
    return values;
  }

  // Step (must be checked before range, since "*/15" and "1-5/2" both contain "/")
  if (expr.includes("/")) {
    return parseStep(expr, config);
  }

  // Range
  if (expr.includes("-")) {
    return parseRange(expr, config);
  }

  // Single numeric value
  const num = Number(expr);
  if (!Number.isInteger(num) || String(num) !== expr.trim()) {
    throw new SyntaxError(`Invalid field token "${expr}" — expected an integer, wildcard, range, or step`);
  }
  assertInRange(num, config.min, config.max, expr);
  return [num];
}

function parseFieldExpression(expr: string, config: FieldConfig): number[] {
  if (typeof expr !== "string" || expr.length === 0) {
    throw new SyntaxError(`Field "${config.name}" expression must be a non-empty string`);
  }

  // Comma-separated list — expand each part independently, deduplicate, sort
  if (expr.includes(",")) {
    const parts = expr.split(",");
    if (parts.some((p) => p.trim().length === 0)) {
      throw new SyntaxError(`Empty token in comma-separated list "${expr}" for field "${config.name}"`);
    }

    const seen = new Set<number>();
    for (const part of parts) {
      const values = parseSingleField(part.trim(), config);
      for (const v of values) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSingleField(expr, config);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 whitespace-separated fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute: parseFieldExpression(minuteExpr, FIELD_CONFIGS[0]),
    hour: parseFieldExpression(hourExpr, FIELD_CONFIGS[1]),
    dayOfMonth: parseFieldExpression(dayOfMonthExpr, FIELD_CONFIGS[2]),
    month: parseFieldExpression(monthExpr, FIELD_CONFIGS[3]),
    dayOfWeek: parseFieldExpression(dayOfWeekExpr, FIELD_CONFIGS[4]),
  };
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options === null || typeof options !== "object") {
      throw new TypeError("Options must be a non-null object");
    }

    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError("refillRate must be a positive finite number");
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + tokensToAdd
      );
      this.lastRefillTime = now;
    }
  }

  private validateTokenArg(tokens: number, label = "tokens"): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`${label} must be a non-negative finite number`);
    }
    if (!Number.isInteger(tokens)) {
      throw new TypeError(`${label} must be an integer`);
    }
  }

  tryConsume(tokens = 1): boolean {
    this.validateTokenArg(tokens);

    if (tokens === 0) return true;

    // A request larger than the bucket capacity can never be satisfied
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens = 1): Promise<void> {
    try {
      this.validateTokenArg(tokens);
    } catch (err) {
      return Promise.reject(err);
    }

    if (tokens === 0) return Promise.resolve();

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
        )
      );
    }

    return new Promise<void>((resolve) => {
      const attempt = (): void => {
        this.refill();

        if (this.currentTokens >= tokens) {
          this.currentTokens -= tokens;
          resolve();
          return;
        }

        // Compute the minimum time until enough tokens will be available
        const deficit = tokens - this.currentTokens;
        const waitMs = Math.ceil(
          (deficit / this.refillRate) * this.refillIntervalMs
        );

        setTimeout(attempt, Math.max(1, waitMs));
      };

      attempt();
    });
  }
}

export default RateLimiter;

export default class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed >= this.refillIntervalMs) {
      const intervals = Math.floor(elapsed / this.refillIntervalMs);
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + tokensToAdd
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError(`tokens (${tokens}) exceeds maxTokens (${this.maxTokens})`)
      );

    return new Promise<void>((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();

        const tokensNeeded = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
        const msUntilNextRefill =
          this.refillIntervalMs - (Date.now() - this.lastRefillTime);
        const waitMs =
          (intervalsNeeded - 1) * this.refillIntervalMs +
          Math.max(0, msUntilNextRefill);

        setTimeout(attempt, Math.max(0, waitMs));
      };

      attempt();
    });
  }
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(expr: string, min: number, max: number): number[] {
  const results = new Set<number>();

  const parts = expr.split(",");

  for (const part of parts) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    const stepMatch = trimmed.match(/^(\*|(\d+)-(\d+))\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[4], 10);
      if (step <= 0) throw new Error(`Invalid step value: ${step}`);

      let rangeMin: number;
      let rangeMax: number;

      if (stepMatch[1] === "*") {
        rangeMin = min;
        rangeMax = max;
      } else {
        rangeMin = parseInt(stepMatch[2], 10);
        rangeMax = parseInt(stepMatch[3], 10);
      }

      if (rangeMin < min || rangeMax > max || rangeMin > rangeMax) {
        throw new Error(`Range ${rangeMin}-${rangeMax} out of bounds [${min}, ${max}]`);
      }

      for (let i = rangeMin; i <= rangeMax; i += step) results.add(i);
      continue;
    }

    const rangeMatch = trimmed.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const start = parseInt(rangeMatch[1], 10);
      const end = parseInt(rangeMatch[2], 10);

      if (start < min || end > max) {
        throw new Error(`Range ${start}-${end} out of bounds [${min}, ${max}]`);
      }
      if (start > end) {
        throw new Error(`Range start ${start} is greater than end ${end}`);
      }

      for (let i = start; i <= end; i++) results.add(i);
      continue;
    }

    const numMatch = trimmed.match(/^(\d+)$/);
    if (numMatch) {
      const value = parseInt(numMatch[1], 10);
      if (value < min || value > max) {
        throw new Error(`Value ${value} out of bounds [${min}, ${max}]`);
      }
      results.add(value);
      continue;
    }

    throw new Error(`Invalid cron field expression: "${trimmed}"`);
  }

  return Array.from(results).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (!expression || typeof expression !== "string") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}. Format: "minute hour dayOfMonth month dayOfWeek"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  const [minuteRange, hourRange, domRange, monthRange, dowRange] =
    fieldNames.map((name) => FIELD_RANGES[name]);

  return {
    minute: parseField(minuteExpr, ...minuteRange),
    hour: parseField(hourExpr, ...hourRange),
    dayOfMonth: parseField(domExpr, ...domRange),
    month: parseField(monthExpr, ...monthRange),
    dayOfWeek: parseField(dowExpr, ...dowRange),
  };
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function processInline(text: string): string {
  if (!text) return '';

  // Extract code spans first to protect their contents
  const codeSpans: string[] = [];
  let s = text.replace(/`([^`\n]+)`/g, (_m, code) => {
    codeSpans.push(`<code>${escapeHtml(code)}</code>`);
    return `\x00CS${codeSpans.length - 1}\x00`;
  });

  // Escape HTML in remaining text before inserting markup
  s = escapeHtml(s);

  // Links [text](url)
  s = s.replace(/\[([^\]]*)\]\(([^)]*)\)/g, (_m, linkText, url) =>
    `<a href="${url}">${linkText}</a>`
  );

  // Bold: ** or __ (must be processed before italic)
  s = s.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  s = s.replace(/(?<![_\w])__(.+?)__(?![_\w])/g, '<strong>$1</strong>');

  // Italic: * or _
  s = s.replace(/\*(.+?)\*/g, '<em>$1</em>');
  s = s.replace(/(?<![_\w])_(.+?)_(?![_\w])/g, '<em>$1</em>');

  // Restore protected code spans
  s = s.replace(/\x00CS(\d+)\x00/g, (_m, i) => codeSpans[parseInt(i, 10)]);

  return s;
}

interface ListItem {
  indent: number;
  content: string;
}

function buildList(lines: string[]): string {
  const items: ListItem[] = lines
    .filter(line => /^\s*[-*]\s/.test(line))
    .map(line => ({
      indent: line.match(/^(\s*)/)?.[1].length ?? 0,
      content: line.replace(/^\s*[-*]\s+/, ''),
    }));

  if (items.length === 0) return '';

  const baseDepth = Math.min(...items.map(it => it.indent));

  function render(subset: ListItem[], depth: number): string {
    let html = '<ul>';
    let i = 0;

    while (i < subset.length) {
      // Skip items that don't belong to this depth level (shouldn't normally occur)
      if (subset[i].indent !== depth) {
        i++;
        continue;
      }

      html += `<li>${processInline(subset[i].content)}`;
      i++;

      // Collect all immediately following deeper-indented items as children
      const children: ListItem[] = [];
      while (i < subset.length && subset[i].indent > depth) {
        children.push(subset[i++]);
      }

      if (children.length > 0) {
        const childDepth = Math.min(...children.map(c => c.indent));
        html += render(children, childDepth);
      }

      html += '</li>';
    }

    html += '</ul>';
    return html;
  }

  return render(items, baseDepth);
}

