export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: keyof CronFields;
  min: number;
  max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
] as const;

const FIELD_COUNT = 5;

function assertInteger(value: number, context: string): void {
  if (!Number.isInteger(value)) {
    throw new Error(`${context}: expected integer, got ${value}`);
  }
}

function clampToRange(values: number[], min: number, max: number, context: string): number[] {
  for (const v of values) {
    if (v < min || v > max) {
      throw new RangeError(
        `${context}: value ${v} is out of valid range [${min}, ${max}]`
      );
    }
  }
  return values;
}

function parseNumber(token: string, context: string): number {
  const trimmed = token.trim();
  if (trimmed === "" || !/^-?\d+$/.test(trimmed)) {
    throw new SyntaxError(`${context}: "${trimmed}" is not a valid integer`);
  }
  const n = parseInt(trimmed, 10);
  assertInteger(n, context);
  return n;
}

function expandRange(start: number, end: number, context: string): number[] {
  if (start > end) {
    throw new RangeError(
      `${context}: range start ${start} exceeds end ${end}`
    );
  }
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, min: number, max: number, context: string): number[] {
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new SyntaxError(`${context}: empty segment`);
  }

  // Wildcard with optional step: "*" or "*/n"
  if (trimmed === "*") {
    return expandRange(min, max, context);
  }

  if (trimmed.startsWith("*/")) {
    const stepPart = trimmed.slice(2);
    const step = parseNumber(stepPart, `${context} (step)`);
    if (step <= 0) {
      throw new RangeError(`${context}: step value must be positive, got ${step}`);
    }
    if (step > max - min) {
      throw new RangeError(
        `${context}: step ${step} exceeds range size ${max - min}`
      );
    }
    const result: number[] = [];
    for (let i = min; i <= max; i += step) {
      result.push(i);
    }
    return result;
  }

  // Range with optional step: "a-b" or "a-b/n"
  if (trimmed.includes("-")) {
    const slashIndex = trimmed.indexOf("/");
    const rangePart = slashIndex === -1 ? trimmed : trimmed.slice(0, slashIndex);
    const stepPart = slashIndex === -1 ? null : trimmed.slice(slashIndex + 1);

    const dashIndex = rangePart.indexOf("-");
    if (dashIndex <= 0) {
      throw new SyntaxError(`${context}: malformed range "${rangePart}"`);
    }

    const startStr = rangePart.slice(0, dashIndex);
    const endStr = rangePart.slice(dashIndex + 1);

    if (endStr.includes("-")) {
      throw new SyntaxError(`${context}: ambiguous range "${rangePart}"`);
    }

    const start = parseNumber(startStr, `${context} (range start)`);
    const end = parseNumber(endStr, `${context} (range end)`);

    clampToRange([start], min, max, context);
    clampToRange([end], min, max, context);

    const rangeValues = expandRange(start, end, context);

    if (stepPart !== null) {
      const step = parseNumber(stepPart, `${context} (range step)`);
      if (step <= 0) {
        throw new RangeError(`${context}: step value must be positive, got ${step}`);
      }
      const stepped: number[] = [];
      for (let i = 0; i < rangeValues.length; i += step) {
        stepped.push(rangeValues[i]);
      }
      return stepped;
    }

    return rangeValues;
  }

  // Step on a plain number: "5/n" — not standard, but guard against it
  if (trimmed.includes("/")) {
    throw new SyntaxError(
      `${context}: step notation "${trimmed}" requires a range or wildcard`
    );
  }

  // Plain number
  const n = parseNumber(trimmed, context);
  clampToRange([n], min, max, context);
  return [n];
}

function parseField(expression: string, config: FieldConfig): number[] {
  const context = `field "${config.name}"`;

  if (typeof expression !== "string") {
    throw new TypeError(`${context}: expected string, got ${typeof expression}`);
  }

  const parts = expression.split(",");

  if (parts.length === 0) {
    throw new SyntaxError(`${context}: empty expression`);
  }

  const allValues = new Set<number>();

  for (const part of parts) {
    const values = parseSegment(part, config.min, config.max, context);
    for (const v of values) {
      allValues.add(v);
    }
  }

  return Array.from(allValues).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron: expected string expression, got ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new SyntaxError("parseCron: expression must not be empty");
  }

  // Collapse multiple whitespace characters between fields
  const fields = trimmed.split(/\s+/);

  if (fields.length !== FIELD_COUNT) {
    throw new SyntaxError(
      `parseCron: expected ${FIELD_COUNT} fields, got ${fields.length} in "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_COUNT; i++) {
    const config = FIELD_CONFIGS[i];
    result[config.name] = parseField(fields[i], config);
  }

  return result;
}

export default parseCron;

export class RateLimiter {
