    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + tokensToAdd
      );
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError(`tokens (${tokens}) exceeds maxTokens (${this.maxTokens})`)
      );

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(
          1,
          intervalsNeeded * this.refillIntervalMs -
            (Date.now() - this.lastRefillTime)
        );

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Readonly<Record<keyof CronFields, FieldConfig>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: ReadonlyArray<keyof CronFields> = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function parseStrictInteger(raw: string, fieldName: string): number {
  // Guard against leading/trailing whitespace, empty string, floats, and non-numeric
  if (raw === "" || raw.trim() !== raw) {
    throw new Error(`Invalid numeric token "${raw}" in field "${fieldName}"`);
  }
  const n = Number(raw);
  if (!Number.isFinite(n) || !Number.isInteger(n)) {
    throw new Error(`Non-integer value "${raw}" in field "${fieldName}"`);
  }
  return n;
}

function assertInRange(n: number, min: number, max: number, fieldName: string): void {
  if (n < min || n > max) {
    throw new Error(
      `Value ${n} out of valid range [${min}–${max}] for field "${fieldName}"`
    );
  }
}

function parseFieldNumber(
  raw: string, fieldName: string, min: number, max: number
): number {
  const n = parseStrictInteger(raw, fieldName);
  assertInRange(n, min, max, fieldName);
  return n;
}

function parseStep(raw: string, fieldName: string): number {
  if (raw === "") {
    throw new Error(`Empty step value in field "${fieldName}"`);
  }
  const step = parseStrictInteger(raw, fieldName);
  if (step < 1) {
    throw new Error(`Step must be ≥ 1, got ${step} in field "${fieldName}"`);
  }
  return step;
}

function expandRange(start: number, end: number, step: number): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseToken(
  token: string, fieldName: string, { min, max }: FieldConfig
): number[] {
  if (token === "") {
    throw new Error(`Empty token in field "${fieldName}"`);
  }

  // ── Wildcard: "*" or "*/step" ─────────────────────────────────────────────
  if (token[0] === "*") {
    if (token === "*") {
      return expandRange(min, max, 1);
    }
    if (token.startsWith("*/")) {
      const step = parseStep(token.slice(2), fieldName);
      return expandRange(min, max, step);
    }
    throw new Error(`Malformed wildcard expression "${token}" in field "${fieldName}"`);
  }

  // ── Range: "n-m" or "n-m/step" ───────────────────────────────────────────
  // Find the first dash that is a range separator (not a minus on the first char).
  const dashIdx = token.indexOf("-");
  if (dashIdx > 0) {
    const slashIdx  = token.indexOf("/");
    const rangePart = slashIdx >= 0 ? token.slice(0, slashIdx) : token;
    const stepStr   = slashIdx >= 0 ? token.slice(slashIdx + 1) : null;

    const localDash = rangePart.indexOf("-");
    const startStr  = rangePart.slice(0, localDash);
    const endStr    = rangePart.slice(localDash + 1);

    if (startStr === "" || endStr === "") {
      throw new Error(`Malformed range "${token}" in field "${fieldName}"`);
    }

    const start = parseFieldNumber(startStr, fieldName, min, max);
    const end   = parseFieldNumber(endStr,   fieldName, min, max);

    if (start > end) {
      throw new Error(
        `Range start (${start}) exceeds end (${end}) in field "${fieldName}"`
      );
    }

    const step = stepStr !== null ? parseStep(stepStr, fieldName) : 1;
    return expandRange(start, end, step);
  }

  // ── Value with step: "n/step" ─────────────────────────────────────────────
  const slashIdx = token.indexOf("/");
  if (slashIdx >= 0) {
    const valuePart = token.slice(0, slashIdx);
    const stepPart  = token.slice(slashIdx + 1);
    const start     = parseFieldNumber(valuePart, fieldName, min, max);
    const step      = parseStep(stepPart, fieldName);
    return expandRange(start, max, step);
  }

  // ── Plain integer ─────────────────────────────────────────────────────────
  return [parseFieldNumber(token, fieldName, min, max)];
}

function parseField(
  raw: string, fieldName: string, config: FieldConfig
): number[] {
  if (raw === "" || raw !== raw.trim()) {
    throw new Error(
      `Field "${fieldName}" has surrounding whitespace or is empty`
    );
  }

  const segments = raw.split(",");

  // Guard: trailing/leading comma produces empty segments
  if (segments.some(s => s === "")) {
    throw new Error(
      `Empty segment in comma-list for field "${fieldName}": "${raw}"`
    );
  }

  const seen = new Set<number>();
  for (const segment of segments) {
    for (const value of parseToken(segment, fieldName, config)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression requires exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(parts[i], fieldName, FIELD_CONFIGS[fieldName]);
  }

  return result;
}

export default parseCron;

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Array<{ tokens: number; resolve: () => void }>;
  private scheduled: boolean;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options == null || typeof options !== "object") {
      throw new TypeError("Options must be a non-null object");
    }

    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError("refillRate must be a positive finite number");
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waiters = [];
    this.scheduled = false;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed < this.refillIntervalMs) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    const tokensToAdd = intervals * this.refillRate;
    this.currentTokens = Math.min(
      this.maxTokens,
      this.currentTokens + tokensToAdd
    );
    // Advance the refill baseline to the last completed interval boundary
    this.lastRefillTime += intervals * this.refillIntervalMs;
  }

  private msUntilSufficient(tokens: number): number {
    if (this.currentTokens >= tokens) return 0;

    const deficit = tokens - this.currentTokens;
    const intervalsNeeded = Math.ceil(deficit / this.refillRate);
    const elapsedSinceLastRefill = Date.now() - this.lastRefillTime;
    // Time until the next refill boundary completes
    const msUntilNextRefill = this.refillIntervalMs - elapsedSinceLastRefill;

    // First interval fills at msUntilNextRefill; each subsequent adds refillIntervalMs
    return msUntilNextRefill + (intervalsNeeded - 1) * this.refillIntervalMs;
  }

  private scheduleWaiterCheck(): void {
    if (this.scheduled || this.waiters.length === 0) return;

    this.applyRefill();

    const first = this.waiters[0];
    const delay = this.msUntilSufficient(first.tokens);

    this.scheduled = true;
    setTimeout(() => {
      this.scheduled = false;
      this.drainWaiters();
      // +1ms buffer guards against sub-millisecond timer imprecision
    }, Math.max(0, delay) + 1);
  }

  private drainWaiters(): void {
    this.applyRefill();

    while (this.waiters.length > 0) {
      const first = this.waiters[0];

      if (this.currentTokens >= first.tokens) {
        this.currentTokens -= first.tokens;
        this.waiters.shift();
        first.resolve();
      } else {
        break;
      }
    }

    if (this.waiters.length > 0) {
      this.scheduleWaiterCheck();
    }
  }

  private validateTokenCount(tokens: number, label = "tokens"): void {
    if (typeof tokens !== "number" || !Number.isFinite(tokens) || tokens < 0) {
      throw new TypeError(`${label} must be a non-negative finite number`);
    }
    if (!Number.isInteger(tokens)) {
      throw new TypeError(`${label} must be an integer`);
    }
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenCount(tokens);

    if (tokens === 0) return true;
    // A request larger than the bucket can never be satisfied
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    if (this.waiters.length > 0) {
      // Defer draining so callers observe a consistent post-reset state
      Promise.resolve().then(() => this.drainWaiters());
    }
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    this.validateTokenCount(tokens);

    if (tokens === 0) return;

    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens}); ` +
          `this request can never be satisfied`
      );
    }

    // Serve immediately only when no one is already waiting (preserves FIFO order)
    if (this.waiters.length === 0 && this.tryConsume(tokens)) {
      return;
    }

    return new Promise<void>((resolve) => {
      this.waiters.push({ tokens, resolve });
      this.scheduleWaiterCheck();
    });
  }
}

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + tokensToAdd
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError(
          `Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`
        )
      );

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const elapsed = Date.now() - this.lastRefillTime;
        const waitMs = Math.max(
          1,
          intervalsNeeded * this.refillIntervalMs - elapsed
        );

        setTimeout(attempt, waitMs);
      };

      attempt();
    });
  }
}

export default RateLimiter;
